"""
MKT Original Language Commentary — Romans chapters 8–10
Run: python3 scripts/zc-original-romans-8-10.py

Source data used:
- data/interlinear/romans.json
- data/translation/glossary-greek.json (sarx G4561 disp=4, pneuma G4151 disp=3,
  dikaiosyne G1343 disp=4, pistis G4102 disp=3, nomos G3551 disp=3)
- data/translation/notes/romans.json
- data/translation/draft/mediating/romans.json
- data/commentary/ellicott/romans.json
- data/commentary/mkt-original/romans.json (read ch.1-3 for continuity)

Key decisions in this range:
- 8:3 peri hamartias — "as a sin offering" (the LXX technical term for chaṭṭāʾt)
  is a live option but "for sin" is also possible; commentary notes both.
- 8:20 mataiotēti — the LXX rendering of hebel (vanity/futility); activates
  Ecclesiastes register as well as Gen 3 curse.
- 8:28 panta synergei — textual variant: some MSS add ho theos as subject; the
  impersonal reading ("all things work together") and the personal reading
  ("God works all things together") are both defensible; commentary notes this.
- 9:5 ho ōn epi pantōn theos — the most disputed punctuation in Romans; whether
  Paul attributes deity to Christ here depends on whether the doxological clause
  belongs to the previous antecedent or begins an independent sentence.
- 9:13 misein — "hated" in the Mal 1:3 quotation is the Hebraic idiom for
  relative disfavor (choosing one over another), not divine malice; commentary
  clarifies without softening.
- 10:4 telos nomou Christos — both "end" (termination) and "goal" (telos as
  purpose) are linguistically attested; the context (Israel failed to reach the
  law's goal, v.31) favors the goal/fulfillment reading, though both are present.
- Terminology continuity from ch.1-3: logizomai = reckon/impute, dikaiosyne theou
  = God's own saving righteousness, nomos without article = law-principle,
  huiothesia = adoption, ekklesia = the called community.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ROMANS = {
  "8": {
    "1": '<p><strong>κατάκριμα</strong> (condemnation, G2631) — a legal verdict, not merely a state of guilt; the compound noun (<em>kata-</em> + <em>krima</em>) specifies a sentence handed down, not just liability. The present declarative form ("there is now") rather than a future promise marks the verdict as already in force. <strong>ἐν Χριστῷ Ἰησοῦ</strong> — the locative sphere (<em>en</em> = in) identifies the domain in which the no-condemnation verdict holds; it is not a general amnesty but a status belonging to those who are in Christ.</p>',
    "2": '<p><strong>ὁ νόμος τοῦ πνεύματος τῆς ζωῆς</strong> (the law of the Spirit of life) — the triple genitive chain: the Spirit\'s law, which is characterized by life. Paul uses <em>nomos</em> (G3551, disp=3) for both Mosaic Torah and governing principles; here the Spirit operates with the same normative authority the law claimed but could not exercise. <strong>ἠλευθέρωσεν</strong> (has set free, aorist active, G1659) — the aorist marks a decisive past liberation, not an ongoing process.</p><p><strong>ἀπὸ τοῦ νόμου τῆς ἁμαρτίας καὶ τοῦ θανάτου</strong> (from the law of sin and death) — sin and death operate together as a governing power-pair; ch.7\'s "law of sin" and ch.5\'s entry of death are here named as the complex from which the Spirit\'s law liberates.</p>',
    "3": '<p><strong>τὸ ἀδύνατον τοῦ νόμου</strong> (the impossibility of the law, G102) — an articular adjective used as a substantive: "the impossible thing the law had"; the law was constitutionally incapable of doing what God did in Christ. <strong>ἐν ᾧ ἠσθένει διὰ τῆς σαρκός</strong> (in which it was weakened through the flesh, G4561 disp=4) — the law\'s weakness is not intrinsic but derives from the flesh it addressed; the law was adequate to define righteousness but powerless to produce it in sinful human nature.</p><p><strong>ἐν ὁμοιώματι σαρκὸς ἁμαρτίας</strong> (in the likeness of sinful flesh, G3667) — the precise formulation avoids both docetism and the implication that Christ had sinful flesh; <em>homoiōmati</em> asserts real resemblance to sinful flesh, not identity with its fallenness. <strong>καὶ περὶ ἁμαρτίας</strong> (and concerning sin / as a sin offering) — <em>peri hamartias</em> is the LXX technical term for the sin offering (<em>ḥaṭṭāʾt</em>) in Leviticus 4-5; whether Paul invokes the sacrificial category specifically is debated, but the LXX resonance is intentional.</p>',
    "4": '<p><strong>τὸ δικαίωμα τοῦ νόμου</strong> (the righteous requirement of the law, G1345) — the singular <em>dikaiōma</em> (not plural works) suggests the comprehensive moral demand of the law as a unity, not individual commandments. <strong>πληρωθῇ ἐν ἡμῖν</strong> (might be fulfilled in us, aorist passive subjunctive) — the passive indicates the Spirit as the agent; the fulfillment is something accomplished in believers, not by them through effort. The purpose clause (<em>hina</em>) grounds the entire incarnation-and-condemnation sequence of v.3.</p>',
    "5": '<p><strong>κατὰ σάρκα / κατὰ πνεῦμα</strong> (according to flesh / according to Spirit, G4561/G4151) — the <em>kata</em> preposition specifies the governing standard or norm; to live "according to X" is to have X as the controlling orientation. <strong>φρονοῦσιν</strong> (have their mind set on, G5426) — <em>phroneō</em> is the attitude-and-orientation verb Paul uses in Phil 2 and 4; it describes a deep dispositional set, not merely occasional thoughts.</p>',
    "6": '<p><strong>τὸ φρόνημα τῆς σαρκός</strong> (the mind of the flesh, G5427) — <em>phronēma</em> is the substantive of <em>phroneō</em>: the settled mindset or orientation of the flesh. <strong>ζωὴ καὶ εἰρήνη</strong> (life and peace) — the two words follow naturally from the Spirit\'s orientation; peace (<em>eirēnē</em>) here is the comprehensive shalom of right relationship with God, not mere tranquility.</p>',
    "7": '<p><strong>ἔχθρα εἰς θεόν</strong> (enmity/hostility toward God, G2189) — the abstract noun is strong: not merely neutral indifference to God but active relational opposition. <strong>τῷ γὰρ νόμῳ τοῦ θεοῦ οὐχ ὑποτάσσεται</strong> (for it does not submit to God\'s law) — the present tense describes a standing incapacity; <em>hypotassō</em> (G5293, submit) is the military-hierarchical verb for being under authority, which the flesh structurally refuses.</p>',
    "8": '<p><strong>οἱ δὲ ἐν σαρκὶ ὄντες θεῷ ἀρέσαι οὐ δύνανται</strong> (those who are in the realm of the flesh cannot please God) — <em>ou dynantai</em> = are not able; the impossibility is constitutional, not circumstantial. <strong>areskō</strong> (G700, please) appeared at 15:1-3 for pleasing neighbor vs. self; here the antithesis is made absolute: the flesh-governed person cannot orient toward God\'s pleasure at all.</p>',
    "9": '<p><strong>εἴπερ πνεῦμα θεοῦ οἰκεῖ ἐν ὑμῖν</strong> (if indeed the Spirit of God dwells in you, G3611) — <em>eiper</em> = if truly, since; the condition is treated as assumed to be true for the addressees. <strong>εἰ δέ τις πνεῦμα Χριστοῦ οὐκ ἔχει, οὗτος οὐκ ἔστιν αὐτοῦ</strong> (but if anyone does not have the Spirit of Christ, this one does not belong to him) — the Spirit of God and the Spirit of Christ are used interchangeably, indicating Paul\'s high Christology.</p>',
    "10": '<p><strong>τὸ μὲν σῶμα νεκρὸν διὰ ἁμαρτίαν</strong> (the body is dead because of sin) — the present tense describes the bodily condition under the Adamic curse; death has already taken up residence in the mortal body even for the believer. <strong>τὸ δὲ πνεῦμα ζωὴ διὰ δικαιοσύνην</strong> (but the Spirit is life because of righteousness) — the antithesis is not body vs. soul but two dimensions of current existence; the Spirit as life corresponds to the righteousness enacted in Christ.</p>',
    "11": '<p><strong>ὁ ἐγείρας Χριστὸν ἐκ νεκρῶν</strong> (the one who raised Christ from the dead) — the repeated resurrection reference is the ground of present hope. <strong>ζωοποιήσει</strong> (will give life to, future active, G2227) — the future tense is eschatological: not a present experience but a coming transformation. <strong>διὰ τοῦ ἐνοικοῦντος αὐτοῦ πνεύματος ἐν ὑμῖν</strong> (through his Spirit dwelling in you) — the instrument of future bodily resurrection is the Spirit already present; the indwelling Spirit is the pledge of what the body will receive.</p>',
    "12": '<p><strong>ὀφειλέται ἐσμέν</strong> (we are debtors, G3781) — the same debt-obligation word as 1:14 ("I am a debtor to Greeks and barbarians"); here the debt is framed negatively: we do not owe the flesh anything. <strong>κατὰ σάρκα ζῆν</strong> (to live according to the flesh) — the articular infinitive of the obligation negated; the obligation-structure of debt is invoked to describe the believer\'s non-obligation to the flesh-principle.</p>',
    "13": '<p><strong>εἰ κατὰ σάρκα ζῆτε, μέλλετε ἀποθνῄσκειν</strong> (if you live according to the flesh, you are about to die) — the present of <em>mellō</em> indicates imminence or settled trajectory; flesh-oriented life is already on the path toward death. <strong>εἰ δὲ πνεύματι τὰς πράξεις τοῦ σώματος θανατοῦτε, ζήσεσθε</strong> (but if by the Spirit you put to death the practices of the body, you will live) — <em>thanatoō</em> (G2289) is the mortification verb; the future <em>zēsesthe</em> is eschatological.</p>',
    "14": '<p><strong>ὅσοι πνεύματι θεοῦ ἄγονται</strong> (as many as are led by the Spirit of God) — present passive: an ongoing being-led; <em>agō</em> (G71) is the leading of guidance rather than compulsion. <strong>οὗτοι υἱοί εἰσιν θεοῦ</strong> (these are children of God) — the predication is without qualification; the Spirit-led are, not merely shall be, God\'s children.</p>',
    "15": '<p><strong>πνεῦμα υἱοθεσίας</strong> (spirit of adoption, G5206) — <em>huiothesia</em> is the formal legal term for adoption: the full conferral of all rights and status of a son. The Spirit does not merely indicate sonship but constitutes it. <strong>Ἀββά, ὁ πατήρ</strong> (Abba, Father) — the Aramaic vocative <em>Abba</em> followed by its Greek equivalent; the double form suggests the actual prayer-language of bilingual communities. The same cry appears in Gal 4:6 where the Spirit cries it in believers.</p>',
    "16": '<p><strong>αὐτὸ τὸ πνεῦμα</strong> (the Spirit himself, emphatic) — the reflexive adjective <em>auto</em> placed before the noun is emphatic: not a human impression but the Spirit himself as the primary witness. <strong>συμμαρτυρεῖ τῷ πνεύματι ἡμῶν</strong> (co-witnesses with our spirit, G4828) — the compound prefix <em>sym-</em> indicates joint testimony: two witnesses together. The Spirit is not the only witness but adds his testimony alongside the believer\'s inner witness.</p>',
    "17": '<p><strong>κληρονόμοι μὲν θεοῦ, συγκληρονόμοι δὲ Χριστοῦ</strong> (heirs of God and co-heirs with Christ, G2818/G4789) — the compound <em>syn-klēronomoi</em> is rare; co-inheritance with Christ means the same inheritance belonging to the Son is shared with those in him. <strong>εἴπερ συμπάσχομεν ἵνα καὶ συνδοξασθῶμεν</strong> (if indeed we suffer together, so that we may also be glorified together) — the <em>sym-</em> prefix on both verbs insists on the participation-with-Christ structure of both present suffering and future glory.</p>',
    "18": '<p><strong>τοῦ νῦν καιροῦ</strong> (the present time, G2540) — <em>kairos</em> is qualitative time (the appointed, significant moment) rather than <em>chronos</em>; Paul frames the present as a defined eschatological moment. <strong>τὴν μέλλουσαν δόξαν ἀποκαλυφθῆναι εἰς ἡμᾶς</strong> (the coming glory to be revealed into/toward us) — the infinitive <em>apokaluphthēnai</em> echoes the revelation language of 1:17-18; the glory is not developed from within but revealed from outside.</p>',
    "19": '<p><strong>ἡ ἀποκαραδοκία τῆς κτίσεως</strong> (the eager expectation of creation, G603) — <em>apokaradokia</em> is a rare compound (only here and Phil 1:20); it suggests stretching the neck forward to see something coming. Creation is personified with this intense forward-looking posture. <strong>τὴν ἀποκάλυψιν τῶν υἱῶν τοῦ θεοῦ ἀπεκδέχεται</strong> (awaits the revelation of the children of God) — the verb <em>apekdechomai</em> (G553) implies focused patient waiting; the same verb is used for the Spirit\'s firstfruits awaiting adoption in v.23.</p>',
    "20": '<p><strong>τῇ ματαιότητι ὑπετάγη</strong> (was subjected to futility, G3153) — <em>mataiotēs</em> is the LXX word for the Hebrew <em>hebel</em> of Ecclesiastes; Paul\'s choice activates both the Ecclesiastes meditation on created vanity and the Gen 3 curse. The passive <em>hypetage</em> and the subsequent phrase indicate divine action, not creaturely failure. <strong>οὐχ ἑκοῦσα</strong> (not willingly, G1635) — emphasizing that the creation did not choose its condition; it was subjected from outside, by God\'s judicial response to Adam\'s sin.</p>',
    "21": '<p><strong>ὅτι καὶ αὐτὴ ἡ κτίσις ἐλευθερωθήσεται</strong> (that creation itself will be set free, G1659) — future passive; the same liberation verb as 8:2. The liberation has a direction: <strong>εἰς τὴν ἐλευθερίαν τῆς δόξης τῶν τέκνων τοῦ θεοῦ</strong> (into the freedom of the glory of the children of God) — a triple genitive chain; creation\'s liberation is described in terms of sharing the freedom that characterizes the glorified children of God.</p>',
    "22": '<p><strong>πᾶσα ἡ κτίσις συστενάζει καὶ συνωδίνει</strong> (the whole creation groans together and travails together, G4959/G4944) — both verbs carry the <em>syn-</em> prefix of joint participation; the groaning is unified across the created order. <strong>ἄχρι τοῦ νῦν</strong> (up to the present moment) — the temporal limit: the groaning is continuous from the curse until now.</p>',
    "23": '<p><strong>ἀπαρχὴν τοῦ πνεύματος ἔχοντες</strong> (having the firstfruits of the Spirit, G536) — the genitive is probably appositive: the firstfruits which consist of the Spirit. The firstfruits consecrate and pledge the full harvest; the Spirit\'s presence is the pledge of the full inheritance to come. <strong>υἱοθεσίαν ἀπεκδεχόμενοι</strong> (awaiting adoption, G5206) — the same adoption word as v.15; though believers already have the Spirit of adoption, the full outward realization of sonship (bodily resurrection) is still awaited.</p>',
    "24": '<p><strong>τῇ γὰρ ἐλπίδι ἐσώθημεν</strong> (for we were saved in/by hope, G1680) — the aorist passive <em>esōthēmen</em> marks the past event of salvation, but the dative <em>elpidi</em> qualifies its character: it was a salvation that had hope as its mode. <strong>ἐλπὶς δὲ βλεπομένη οὐκ ἔστιν ἐλπίς</strong> (hope that is seen is not hope) — an axiomatic statement; hope requires an object not yet possessed.</p>',
    "25": '<p><strong>δι᾽ ὑπομονῆς ἀπεκδεχόμεθα</strong> (we await through patient endurance, G5281/G553) — <em>hypomonē</em> is active perseverance through obstacles, not passive waiting; the posture of the believer in the eschatological interval is patient, persistent expectation.</p>',
    "26": '<p><strong>ὑπερεντυγχάνει</strong> (intercedes, G5241) — a Pauline compound hapax; the double prefix suggests intense on-behalf-of intercession. <strong>στεναγμοῖς ἀλαλήτοις</strong> (inarticulate/wordless groanings, G215) — <em>alalētos</em> (not able to be expressed in speech) characterizes the Spirit\'s intercession as operating below the level of human language; the Spirit prays in a register unavailable to the praying believer\'s articulation.</p>',
    "27": '<p><strong>ὁ δὲ ἐραυνῶν τὰς καρδίας</strong> (the one who searches the hearts, G2045) — the present participle describes God\'s continuous activity; the divine heart-searching guarantees that the Spirit\'s inarticulate groanings are correctly received. <strong>κατὰ θεὸν ἐντυγχάνει ὑπὲρ ἁγίων</strong> (intercedes for the saints according to God) — the Spirit\'s intercession is aligned with God\'s own will; it is not separate advocacy but the Spirit advocating from within the divine will.</p>',
    "28": '<p><strong>πάντα συνεργεῖ</strong> (all things work together, G4903) — some manuscripts add <em>ho theos</em> (God) as the subject; the impersonal reading and the personal reading are both textually attested. Either way, the claim is comprehensive: the entire range of experience, not merely good experiences. <strong>τοῖς κατὰ πρόθεσιν κλητοῖς</strong> (those called according to purpose) — the calling is <em>kata prothesin</em>, aligned with divine purpose; the promise is not universal but specifically for those within the covenant of calling.</p>',
    "29": '<p><strong>οὓς προέγνω, καὶ προώρισεν</strong> (those he foreknew he also predestined, G4267/G4309) — the aorists describe historical divine acts; <em>proginōskō</em> in Paul\'s usage often carries covenantal overtones (relational foreknowing). <strong>συμμόρφους τῆς εἰκόνος τοῦ υἱοῦ αὐτοῦ</strong> (conformed to the image of his Son, G4832/G1504) — <em>symmorphous</em> indicates real conformity, not imitation; the goal is actual transformation into the pattern of Christ\'s image. <strong>πρωτότοκον ἐν πολλοῖς ἀδελφοῖς</strong> (firstborn among many siblings, G4416) — the firstborn both precedes and defines what those after him are; Christ is the prototype of the new humanity.</p>',
    "30": '<p><strong>οὓς δὲ προώρισεν, τούτους καὶ ἐκάλεσεν</strong> (those he predestined he also called) — the chain is linked by <em>kai</em> (also) at each step. <strong>οὓς δὲ ἐδόξασεν</strong> (those he glorified) — the aorist is proleptic: the glorification is future in experience but described as already accomplished from the divine perspective, grounded in the certainty of the purpose.</p>',
    "31": '<p><strong>εἰ ὁ θεὸς ὑπὲρ ἡμῶν, τίς καθ᾽ ἡμῶν</strong> (if God is for us, who is against us?) — <em>hyper</em> (for, on behalf of) contrasts with <em>kath\'</em> (against); the rhetorical question expects no credible answer. The theological content is grounded in the golden chain of vv.29-30: the entire history of divine purpose terminates in glorification.</p>',
    "32": '<p><strong>ὅς γε τοῦ ἰδίου υἱοῦ οὐκ ἐφείσατο</strong> (who indeed did not spare his own Son, G5339) — the particle <em>ge</em> is emphatic, pointing to the extreme case; if God did not spare what was most precious (<em>idios</em> = his very own), the argument a fortiori holds for all lesser gifts. <strong>ἀλλὰ ὑπὲρ ἡμῶν πάντων παρέδωκεν αὐτόν</strong> (but for all of us gave him up, G3860) — <em>paredōken</em> is the handing-over verb of 1:24,26,28; now God gives over his Son for humanity\'s benefit, deliberately echoing the judicial handover.</p>',
    "33": '<p><strong>θεὸς ὁ δικαιῶν</strong> (God the one who justifies, present participle) — the present participle describes God\'s ongoing act of justification. The rhetorical question "who will bring charges?" receives the implicit answer: no one, because God the ultimate judge is the one who justifies. The prosecutor and the judge are the same, and the judge has declared acquittal.</p>',
    "34": '<p><strong>Χριστὸς Ἰησοῦς ὁ ἀποθανών</strong> (Christ Jesus who died) — <strong>μᾶλλον δὲ ἐγερθείς</strong> (more than that, raised) — the <em>mallon de</em> intensifies: the resurrection is the more significant ground of confidence. <strong>ὃς καί ἐστιν ἐν δεξιᾷ τοῦ θεοῦ</strong> (who also is at the right hand of God) — the present tense <em>estin</em> marks the session as the current, ongoing reality. <strong>ὃς καὶ ἐντυγχάνει ὑπὲρ ἡμῶν</strong> (who also intercedes for us) — same <em>entynchanō</em> root as the Spirit\'s intercession in v.27; both Spirit and risen Christ intercede.</p>',
    "35": '<p><strong>τίς ἡμᾶς χωρίσει ἀπὸ τῆς ἀγάπης τοῦ Χριστοῦ</strong> (who will separate us from the love of Christ?) — the rhetorical question personifies separation as an agent; the list that follows (tribulation, distress, persecution, famine, nakedness, danger, sword) are adverse circumstances, not divine acts. The question\'s assumption is that nothing in the list constitutes genuine separation.</p>',
    "36": '<p>The Ps 44:22 quotation (LXX 43:22) is appended without a citation formula: <strong>ἕνεκεν σοῦ θανατούμεθα ὅλην τὴν ἡμέραν</strong> (for your sake we are put to death all day long) — present passive describing the continuous condition. <strong>ἐλογίσθημεν ὡς πρόβατα σφαγῆς</strong> (we are counted as sheep for slaughter, G3049) — <em>elogisthēmen</em> uses the same imputation-verb as chs.3-4; the community\'s suffering is "reckoned" as the status of sacrifice.</p>',
    "37": '<p><strong>ὑπερνικῶμεν</strong> (we are more than conquerors, G5245) — a Pauline compound hapax; the prefix <em>hyper-</em> intensifies the already-strong <em>nikaō</em> (to conquer/overcome). <strong>διὰ τοῦ ἀγαπήσαντος ἡμᾶς</strong> (through the one who loved us) — the aorist participle marks a completed act of love (the giving of the Son, v.32) as the ground of present and ongoing victory; the conquest is not our own but through his.</p>',
    "38": '<p><strong>οὔτε θάνατος οὔτε ζωή</strong> (neither death nor life) — the extremes of the temporal spectrum; <strong>οὔτε ἄγγελοι οὔτε ἀρχαί</strong> (neither angels nor rulers/powers) — cosmic personal beings; <strong>οὔτε ἐνεστῶτα οὔτε μέλλοντα</strong> (neither present things nor coming things) — the temporal span. The comprehensiveness of the list is its rhetorical power: no conceivable domain of reality falls outside the claim.</p>',
    "39": '<p><strong>οὔτε ὕψωμα οὔτε βάθος</strong> (neither height nor depth, G5313/G899) — spatial extremes; the terms may carry astrological meaning (zenith/nadir) in the Hellenistic world, implying that even cosmic forces directing fate cannot separate. <strong>τῆς ἀγάπης τοῦ θεοῦ τῆς ἐν Χριστῷ Ἰησοῦ τῷ κυρίῳ ἡμῶν</strong> (the love of God that is in Christ Jesus our Lord) — the final genitive chain grounds the love in its Christological location; it is the love expressed and enacted in the particular person of Christ.</p>'
  },
  "9": {
    "1": '<p><strong>ἀλήθειαν λέγω ἐν Χριστῷ</strong> (I speak truth in Christ) — a three-fold attestation: the claim itself (truth), its domain (<em>en Christō</em>), and the corroboration of conscience. The structure resembles a legal deposition. <strong>συμμαρτυρούσης μοι τῆς συνειδήσεώς μου ἐν πνεύματι ἁγίῳ</strong> (my conscience bearing witness along with me in the Holy Spirit, G4828) — the same <em>symmartureō</em> as 8:16; here conscience and the Spirit function together as co-witnesses.</p>',
    "2": '<p><strong>λύπη μοί ἐστιν μεγάλη</strong> (great sorrow is to me) — the dative of possession emphasizes the sorrow as Paul\'s own internalized possession. <strong>ἀδιάλειπτος ὀδύνη τῇ καρδίᾳ μου</strong> (unceasing anguish/pain to my heart, G88/G3601) — <em>odynē</em> is the sharper word for anguish; <em>adialeiptos</em> = not interrupted, continuous. The intensity establishes that what follows about Israel\'s partial rejection is not triumphalism.</p>',
    "3": '<p><strong>ηὐχόμην</strong> (I was wishing/could wish, imperfect) — the imperfect can indicate an unfulfilled wish in the past: "I was wishing, but cannot." <strong>ἀνάθεμα εἶναι αὐτὸς ἐγὼ ἀπὸ τοῦ Χριστοῦ</strong> (that I myself were accursed/cut off from Christ, G331) — <em>anathema</em> is the Greek for the Hebrew <em>ḥerem</em>, something devoted to God for destruction; Paul\'s willingness to bear the ultimate covenant exclusion for his people\'s sake echoes Moses in Exod 32:32.</p>',
    "4": '<p><strong>υἱοθεσία</strong> (adoption, G5206) — the same term as 8:15,23; Paul now applies it to Israel\'s covenant status as God\'s "firstborn son" (Exod 4:22). <strong>αἱ διαθῆκαι</strong> (the covenants — plural) — the plural is notable; Paul includes multiple covenant administrations. <strong>ἡ νομοθεσία</strong> (the lawgiving, G3548) — a single abstract noun for the whole event of Sinai; unique here in the NT. <strong>ἡ λατρεία</strong> (the worship/cultic service, G2999) — the technical term for the priestly service of the tabernacle and temple.</p>',
    "5": '<p><strong>ὁ ὢν ἐπὶ πάντων θεὸς εὐλογητὸς εἰς τοὺς αἰῶνας</strong> (the one who is over all, God blessed forever) — the most debated punctuation in Romans. If this doxology belongs to the preceding clause about the Messiah\'s human ancestry, it is a high Christological predication (Christ is God over all). If it is an independent doxological sentence, it is praise of God the Father. The relative pronoun <em>ho ōn</em> (the one who is) normally resumes an antecedent; most modern scholars favor the Christological reading.</p>',
    "6": '<p><strong>οὐχ οἷον δὲ ὅτι ἐκπέπτωκεν ὁ λόγος τοῦ θεοῦ</strong> (it is not as though God\'s word has failed, G1601) — <em>ekpiptō</em> = to fall out, fail; the perfect tense emphasizes the ongoing state. <strong>οὐ γὰρ πάντες οἱ ἐξ Ἰσραὴλ οὗτοι Ἰσραήλ</strong> (for not all who are from Israel are Israel) — Paul\'s double use of <em>Israel</em> in one clause creates the internal Israel distinction; physical descent from Jacob does not automatically constitute membership in the covenant people.</p>',
    "7": '<p><strong>οὐδ᾽ ὅτι εἰσὶν σπέρμα Ἀβραάμ</strong> (nor because they are offspring of Abraham) — the argument is cumulative: not all of Israel, not all Abraham\'s descendants. <strong>ἐν Ἰσαὰκ κληθήσεταί σοι σπέρμα</strong> (in Isaac shall offspring be named/called to you, Gen 21:12) — the preposition <em>en</em> may mean "through" (through the line of Isaac) or "in the case of" (in Isaac, as the determining instance); either way, the quotation establishes divine selection within the physical descendants.</p>',
    "8": '<p><strong>τέκνα τῆς ἐπαγγελίας</strong> (children of the promise, G1860) — the genitive is characterizing: children who are what they are by promise, not by birth-sequence. <strong>λογίζεται εἰς σπέρμα</strong> (are reckoned/counted as offspring, G3049) — the imputation-verb <em>logizomai</em> from chs.3-4 appears here, applying the faith-reckoning logic to the question of who counts as Abraham\'s offspring.</p>',
    "9": '<p><strong>ἐπαγγελίας γὰρ ὁ λόγος οὗτος</strong> (for this word is of promise) — <em>logos epangelias</em> (word of promise); the Gen 18:10 text Paul quotes is classified by Paul himself as promise-speech. The promise-nature of the word is the point: it creates what it announces rather than merely describing it.</p>',
    "10": '<p><strong>ἐξ ἑνὸς κοίτην ἔχουσα</strong> (having a conception from one man) — the Greek idiom uses <em>koitē</em> (bed, sexual union) as a euphemism; the point is that unlike the Hagar/Sarah distinction, Rebekah had a single father (Isaac) for both twins, eliminating the argument from different mothers.</p>',
    "11": '<p><strong>οὔπω γὰρ γεννηθέντων μηδὲ πραξάντων τι ἀγαθὸν ἢ κακόν</strong> (for before they were born or had done anything good or bad) — the double negation creates an emphatic statement of the priority of divine choice over human action. <strong>ἡ κατ᾽ ἐκλογὴν πρόθεσις τοῦ θεοῦ μένῃ</strong> (God\'s purpose according to election might stand/remain, G1589/G4286) — <em>menō</em> is the stability verb; the purpose <em>according to election</em> is the ground of the stability.</p>',
    "12": '<p><strong>οὐκ ἐξ ἔργων ἀλλ᾽ ἐκ τοῦ καλοῦντος</strong> (not from works but from the one who calls, G2564) — the same works-versus-calling contrast as Paul\'s full gospel argument (3:20-22); here applied retrospectively to the patriarchal narrative, showing that the faith-works antithesis is not a Christian innovation but the structure of OT election itself.</p>',
    "13": '<p><strong>τὸν Ἰακὼβ ἠγάπησα, τὸν δὲ Ἠσαῦ ἐμίσησα</strong> (Jacob I loved, but Esau I hated, G25/G3404) — quoting Mal 1:2-3 which describes the nations of Israel and Edom, not merely individuals. The "hatred" (<em>miseō</em>) in biblical idiom often means the relative disfavor in a binary choice — the less-chosen one versus the more-chosen; cf. Lk 14:26 where one must "hate" family to follow Jesus. This does not eliminate the force of the word, but the idiom prevents misreading it as personal divine animosity.</p>',
    "14": '<p><strong>μὴ ἀδικία παρὰ τῷ θεῷ</strong> (is there unrighteousness with God?, G93) — <em>para</em> + dative = in the sphere of, alongside; the rhetorical question implies the answer No. <strong>μὴ γένοιτο</strong> — Paul\'s characteristic recoil from the conclusion.</p>',
    "15": '<p><strong>Μωσεῖ γὰρ λέγει</strong> (for he says to Moses) — God is the subject speaking; the citation from Exod 33:19 is given as God\'s own declaration. <strong>ἐλεήσω ὃν ἂν ἐλεῶ καὶ οἰκτιρήσω ὃν ἂν οἰκτίρω</strong> (I will have mercy on whom I have mercy, and I will have compassion on whom I have compassion) — the repetition of the same verb in subjunctive and future creates a tautology of sovereignty: mercy defines itself by itself, not by external criteria.</p>',
    "16": '<p><strong>ἄρα οὖν οὐ τοῦ θέλοντος οὐδὲ τοῦ τρέχοντος</strong> (so then it is not of the one who wills nor of the one who runs) — both participles are articular substantives: the willing person and the running person are human subjects excluded from being the determinative cause. <strong>ἀλλὰ τοῦ ἐλεῶντος θεοῦ</strong> (but of the God who shows mercy) — the genitive of origin: mercy originates in God, not in human striving.</p>',
    "17": '<p><strong>ἐξήγειρά σε</strong> (I raised you up, G1825) — the verb means to raise up to a position of power or prominence; in the Exodus context the primary meaning is "bring onto the stage of history." <strong>ὅπως ἐνδείξωμαι ἐν σοὶ τὴν δύναμίν μου</strong> (so that I might display my power in you) — the purpose is divine self-disclosure; Pharaoh served as an instrument of revelation.</p>',
    "18": '<p><strong>ὃν θέλει ἐλεεῖ, ὃν δὲ θέλει σκληρύνει</strong> (he has mercy on whom he wills, and he hardens whom he wills, G4645) — the parallelism is exact; both mercy and hardening are described as acts of divine will. The hardening is judicial confirmation of a prior human self-hardening, not arbitrary causation.</p>',
    "19": '<p><strong>τί οὖν ἔτι μέμφεται</strong> (why then does he still blame/find fault?, G3201) — <em>memphomai</em> (G3201) is the verb for finding fault with someone who had no choice; the objector\'s premise is that hardening eliminates responsibility. <strong>τῷ γὰρ βουλήματι αὐτοῦ τίς ἀνθέστηκεν</strong> (for who has resisted his will, G1013) — the perfect tense <em>anthestēken</em> = has successfully stood against; the implication is that no one has.</p>',
    "20": '<p><strong>μενοῦνγε ὦ ἄνθρωπε</strong> (on the contrary, O human being, G3304) — <em>menounge</em> is a triple particle combination expressing emphatic counter. <strong>τίς εἶ ὁ ἀνταποκρινόμενος τῷ θεῷ</strong> (who are you, the one who talks back to God?, G470) — <em>antapokrinomai</em> = to reply back against; the compound prefix indicates adversarial counter-argument, not mere questioning.</p>',
    "21": '<p><strong>ἐκ τοῦ αὐτοῦ φυράματος</strong> (from the same lump, G5445) — <em>phyrama</em> is the kneaded lump of clay before shaping; the emphasis on "same lump" establishes the equal starting point, making any differentiation the potter\'s prerogative. <strong>ὃ μὲν εἰς τιμὴν σκεῦος, ὃ δὲ εἰς ἀτιμίαν</strong> (one vessel for honor, another for dishonor) — Paul\'s application is not yet explicit; the next verse presses it toward the vessels of wrath and mercy.</p>',
    "22": '<p><strong>εἰ δὲ θέλων ὁ θεὸς ἐνδείξασθαι τὴν ὀργήν</strong> (but if God, willing to show his wrath) — the <em>ei</em> (if) construction extends from v.22 through v.23 as a single long condition without a stated apodosis; the argument invites the reader to draw their own conclusion. <strong>ἤνεγκεν ἐν πολλῇ μακροθυμίᾳ σκεύη ὀργῆς</strong> (bore with the objects of wrath in great patience, G3116) — the divine patience with those headed for destruction is itself an act of moral restraint, not endorsement.</p>',
    "23": '<p><strong>τὸν πλοῦτον τῆς δόξης αὐτοῦ ἐπὶ σκεύη ἐλέους</strong> (the riches of his glory upon vessels of mercy, G4149) — <em>ploutos</em> (wealth/riches) is Paul\'s word for the fullness and abundance of divine attributes. <strong>ἃ προητοίμασεν εἰς δόξαν</strong> (which he prepared beforehand for glory, G4282) — the aorist of divine preparation; cf. v.22 where the vessels of wrath are described as "fitted for destruction" without specifying the agent of fitting.</p>',
    "24": '<p><strong>οὓς καὶ ἐκάλεσεν ἡμᾶς</strong> (whom he also called — us) — the shift to first person as the antecedent of the vessels of mercy is Paul\'s identification of himself and his community with the objects of divine mercy. <strong>οὐ μόνον ἐξ Ἰουδαίων ἀλλὰ καὶ ἐξ ἐθνῶν</strong> (not only from Jews but also from Gentiles) — the <em>ek</em> + genitive indicates extraction from two different source groups.</p>',
    "25": '<p>Paul quotes Hos 2:23 LXX, applying the restoration-of-Israel oracle to Gentile inclusion: <strong>καλέσω τὸν οὐ λαόν μου λαόν μου</strong> (I will call those who were not my people my people) — the <em>ou</em> negations become positive counterparts under God\'s calling. The application to Gentiles is a bold reading: Hosea addresses faithless Israel; Paul extends it to those who had no covenant standing at all.</p>',
    "26": '<p>Hos 1:10 LXX: <strong>ἐκεῖ κληθήσονται υἱοὶ θεοῦ ζῶντος</strong> (there they will be called children of the living God) — the future passive <em>klēthēsontai</em> describes the transformation of status by divine declaration; the <em>ekei</em> (there) marks the location of reversal as the very place where they were called "not my people."</p>',
    "27": '<p>Isaiah cries out with <em>krazei</em> (present = keeps on crying); Isa 10:22-23: <strong>τὸ ὑπόλειμμα σωθήσεται</strong> (the remnant will be saved) — <em>hypoleimma</em> (G5259, remnant) is the critical term; Isaiah does not contradict the promise but qualifies it: salvation within Israel operates on the remnant principle.</p>',
    "28": '<p><strong>λόγον γὰρ συντελῶν καὶ συντέμνων ποιήσει κύριος ἐπὶ τῆς γῆς</strong> (for the Lord will execute his word, finishing and cutting it short upon the earth) — the two participles <em>syntelōn</em> (completing) and <em>syntemnōn</em> (cutting short) describe swift, decisive execution of the divine word; judgment is both complete and rapid.</p>',
    "29": '<p>Isa 1:9: <strong>εἰ μὴ κύριος σαβαὼθ ἐγκατέλιπεν ἡμῖν σπέρμα</strong> (unless the Lord of Hosts had left us seed/offspring) — <em>sperma</em> (G4690) = seed, offspring; the preservation of even a remnant is characterized as God\'s act of leaving seed behind. The title <em>sabaōth</em> emphasizes God\'s sovereign power to preserve what he chooses.</p>',
    "30": '<p><strong>ἔθνη τὰ μὴ διώκοντα δικαιοσύνην</strong> (Gentiles who were not pursuing righteousness, G1343) — the present participle characterizes the Gentiles\' prior state: not seekers. <strong>κατέλαβεν δικαιοσύνην, δικαιοσύνην δὲ τὴν ἐκ πίστεως</strong> (obtained righteousness — righteousness that is from faith) — the repetition with specification: the righteousness obtained is specifically the faith-righteousness, clarifying which kind was grasped.</p>',
    "31": '<p><strong>Ἰσραὴλ δὲ διώκων νόμον δικαιοσύνης εἰς νόμον οὐκ ἔφθασεν</strong> (but Israel, pursuing a law of righteousness, did not attain the law) — <em>nomos dikaiosynēs</em> (law of righteousness) and <em>eis nomon</em> (to the law) use <em>nomos</em> ambiguously; Israel was pursuing the law as the means of righteousness but failed to reach even the law\'s own standard. The failure is not of effort but of method.</p>',
    "32": '<p><strong>ὅτι οὐκ ἐκ πίστεως ἀλλ᾽ ὡς ἐξ ἔργων</strong> (because not from faith but as if from works) — the adverb <em>hōs</em> (as if) is important: Paul may be indicating that Israel\'s approach was as if the law were a works-system. <strong>προσέκοψαν τῷ λίθῳ τοῦ προσκόμματος</strong> (they stumbled over the stumbling stone, G4350) — aorist indicative: the stumbling already happened; the stone they tripped on was placed by God (v.33).</p>',
    "33": '<p>Paul combines Isa 28:16 and Isa 8:14: <strong>ἰδοὺ τίθημι ἐν Σιὼν λίθον προσκόμματος καὶ πέτραν σκανδάλου</strong> (behold I place in Zion a stone of stumbling and a rock of offense, G4348/G4625) — <em>proskomma</em> (stumbling block) and <em>skandalon</em> (trap/offense) differ in emphasis: the first is what you trip over, the second is what ensnares. <strong>καὶ ὁ πιστεύων ἐπ᾽ αὐτῷ οὐ καταισχυνθήσεται</strong> (and the one believing upon him will not be put to shame, G2617) — the <em>epi</em> + dative construction for faith indicates resting upon or reliance on; shame/dishonor is the judicial-social verdict that faith in the stone averts.</p>'
  },
  "10": {
    "1": '<p><strong>ἡ μὲν εὐδοκία τῆς ἐμῆς καρδίας</strong> (my heart\'s desire/goodwill, G2107) — <em>eudokia</em> is a strong affective noun, the settled disposition of goodwill; Paul\'s desire for Israel\'s salvation is not a mere wish but a deep resolved longing. <strong>ἡ δέησις πρὸς τὸν θεόν</strong> (the prayer/petition to God, G1162) — <em>deēsis</em> is urgent petition; <em>pros ton theon</em> indicates the direction of the plea.</p>',
    "2": '<p><strong>ζῆλον θεοῦ ἔχουσιν</strong> (they have zeal for God, G2205) — the genitive <em>theou</em> is objective: the zeal is directed toward God. Paul affirms this zeal as real, not fabricated. <strong>ἀλλ᾽ οὐ κατ᾽ ἐπίγνωσιν</strong> (but not according to knowledge, G1922) — <em>epignōsis</em> is intensified knowing, full recognition rather than mere acquaintance; the zeal lacks the full cognitive grasp of what God requires.</p>',
    "3": '<p><strong>τὴν τοῦ θεοῦ δικαιοσύνην ἀγνοοῦντες</strong> (being ignorant of God\'s righteousness, G1343 disp=4) — the article (<em>tēn tou theou</em>) makes this the specific divine righteousness Paul has been expounding (cf. 1:17; 3:21-22). <strong>τὴν ἰδίαν ζητοῦντες στῆσαι</strong> (seeking to establish their own, G2398/G2476) — <em>idian</em> = one\'s very own, personal; <em>stēsai</em> (aorist infinitive of <em>histēmi</em> = to make stand, establish) — they were trying to set up their own righteousness as a standing structure before God.</p>',
    "4": '<p><strong>τέλος γὰρ νόμου Χριστός</strong> (Christ is the telos/end of the law, G5056) — the crux turns on the meaning of <em>telos</em>: (1) termination (Christ ended the law\'s period), (2) goal/purpose (Christ is the goal toward which the law pointed). The context of 9:31-33 (Israel failed to reach the law\'s own aim) and 10:5-8 (the law speaks of a righteousness now arrived in Christ) supports the goal/fulfillment reading. Both dimensions may be present, but the telic reading is primary. <strong>εἰς δικαιοσύνην παντὶ τῷ πιστεύοντι</strong> (for righteousness to everyone who believes) — the present participle describes ongoing believing; the righteousness is universally available.</p>',
    "5": '<p><strong>τὴν δικαιοσύνην τὴν ἐκ τοῦ νόμου</strong> (the righteousness from the law) — Paul quotes Lev 18:5 as the law\'s own self-description of its righteousness-logic. <strong>ὁ ποιήσας αὐτὰ ἄνθρωπος ζήσεται ἐν αὐτοῖς</strong> (the person who does them shall live by them) — the life-promise of Torah is conditioned on doing; Paul\'s argument is that this doing-condition has been met in Christ (3:21; 8:4).</p>',
    "6": '<p><strong>ἡ δὲ ἐκ πίστεως δικαιοσύνη οὕτως λέγει</strong> (but the righteousness from faith says thus) — Paul personifies the faith-righteousness as itself speaking; the words that follow are drawn from Deut 30:12-14, which Paul reads Christologically. <strong>μὴ εἴπῃς ἐν τῇ καρδίᾳ σου</strong> (do not say in your heart) — the prohibition against heart-speech introduces the rhetorical conditions the word-of-faith makes unnecessary.</p>',
    "7": '<p><strong>τίς καταβήσεται εἰς τὴν ἄβυσσον</strong> (who will descend into the abyss, G12) — Paul substitutes <em>abyssos</em> (the deep/abyss, the LXX word for Hades) for Deuteronomy\'s "cross the sea"; the reinterpretation (that is, to bring Christ up from the dead) makes the descending a reference to resurrection-from-Hades. The substitution indicates Paul is doing interpretive midrash on the Deut 30 text.</p>',
    "8": '<p><strong>ἐγγύς σου τὸ ῥῆμά ἐστιν</strong> (the word is near you, G4487) — <em>rhēma</em> (G4487) is the spoken/declared word, distinct from <em>logos</em> (G3056); Paul uses <em>rhēma</em> to emphasize the proclaimed, accessible character of the gospel. <strong>τὸ ῥῆμα τῆς πίστεως ὃ κηρύσσομεν</strong> (the word of faith which we proclaim) — the message whose content is faith, or faith\'s own message; the word that calls for and produces faith.</p>',
    "9": '<p><strong>ὅτι ἐὰν ὁμολογήσῃς ἐν τῷ στόματί σου κύριον Ἰησοῦν</strong> (that if you confess with your mouth Jesus as Lord, G3670) — the aorist subjunctive <em>homologēsēs</em> indicates a decisive act of confession; <em>en tō stomati</em> (with/in the mouth) is the organ of public declaration. <strong>Ἰησοῦν κύριον</strong> — the predicate <em>kyrion</em> applied to Jesus claims for him the title the LXX uses for YHWH; this is the confession\'s Christological content.</p>',
    "10": '<p><strong>καρδίᾳ γὰρ πιστεύεται εἰς δικαιοσύνην</strong> (for with the heart one believes to righteousness) — the dative <em>kardia</em> is instrumental; the direction <em>eis dikaiosynēn</em> marks the result. <strong>στόματι δὲ ὁμολογεῖται εἰς σωτηρίαν</strong> (with the mouth one confesses to salvation) — the chiasm of the verse: mouth-to-heart (v.9) becomes heart-to-mouth (v.10); the two faculties each contribute to the complete movement.</p>',
    "11": '<p><strong>πᾶς ὁ πιστεύων ἐπ᾽ αὐτῷ</strong> (everyone who believes upon him, G3956) — the <em>pas</em> (everyone) extends the Isa 28:16 quotation: Paul\'s LXX version adds <em>pas</em> to the original Hebrew, making the universality explicit. <strong>οὐ καταισχυνθήσεται</strong> (will not be put to shame, G2617) — the future passive: the eschatological verdict that cannot shame the one who trusted the stone.</p>',
    "12": '<p><strong>οὐ γάρ ἐστιν διαστολὴ Ἰουδαίου τε καὶ Ἕλληνος</strong> (for there is no distinction between Jew and Greek, G1293) — the same absence-of-distinction language as 3:22; the rhetorical and theological inclusivity holds across both the sin-diagnosis and the salvation-announcement. <strong>ὁ αὐτὸς κύριος πάντων</strong> (the same Lord is Lord of all) — the <em>autos</em> (same) emphasizes identity: the same one Lord, not merely similar lords.</p>',
    "13": '<p>Paul quotes Joel 2:32 (LXX 3:5): <strong>πᾶς ὃς ἂν ἐπικαλέσηται τὸ ὄνομα κυρίου σωθήσεται</strong> (everyone who calls on the name of the Lord will be saved) — the <em>kyrios</em> of Joel refers to YHWH; Paul applies it to Christ, who has been identified as <em>kyrios</em> in the confession of v.9. The transfer of the divine name to Jesus is Paul\'s implicit Christology.</p>',
    "14": '<p><strong>πῶς οὖν ἐπικαλέσωνται εἰς ὃν οὐκ ἐπίστευσαν</strong> (how then can they call on one in whom they have not believed?) — Paul\'s chain of four <em>pōs</em> (how) questions works backward from the outcome (calling) to the precondition (being sent). Each step is logically necessary: you cannot call on one you don\'t believe in; you cannot believe in one you haven\'t heard; you cannot hear without a preacher; there is no preacher without a sender.</p>',
    "15": '<p><strong>πῶς δὲ κηρύξωσιν ἐὰν μὴ ἀποσταλῶσιν</strong> (how will they preach unless they are sent?) — <em>apostellō</em> (G649) is the root of <em>apostolos</em>; the apostle\'s identity is the sent-one. The sending precedes and grounds the preaching. <strong>ὡς ὡραῖοι οἱ πόδες τῶν εὐαγγελιζομένων</strong> (how beautiful are the feet of those who proclaim good news, G5611) — <em>hōraios</em> means timely, in season, beautiful; the beauty is functional-eschatological, not aesthetic.</p>',
    "16": '<p><strong>κύριε, τίς ἐπίστευσεν τῇ ἀκοῇ ἡμῶν</strong> (Lord, who has believed our message?, Isa 53:1) — <em>akoē</em> (G189) = that which is heard, or the act of hearing; in Isa 53:1 it refers to the Servant\'s report/message. Paul uses the word in both senses here and in v.17: the Isa 53 <em>akoē</em> (message rejected) becomes the v.17 <em>akoē</em> (faith-producing hearing).</p>',
    "17": '<p><strong>ἄρα ἡ πίστις ἐξ ἀκοῆς</strong> (so then faith comes from hearing/the message, G189) — <em>ex akoēs</em>: the source of faith is the act of hearing; faith is not self-generated but is produced by the word that is proclaimed. <strong>ἡ δὲ ἀκοὴ διὰ ῥήματος Χριστοῦ</strong> (and hearing through the word of Christ) — the genitive <em>Christou</em>: either the word spoken by Christ or the word whose content is Christ; the latter fits the context, since the gospel Paul preaches is the Christ-word.</p>',
    "18": '<p><strong>εἰς πᾶσαν τὴν γῆν ἐξῆλθεν ὁ φθόγγος αὐτῶν</strong> (their voice went out to all the earth, G5353) — Paul quotes Ps 19:4 about the universal testimony of creation\'s "voice"; the application to the gospel proclamation is a bold typological move. The rhetorical point is Israel\'s inexcusability: the message has gone everywhere, including to Israel.</p>',
    "19": '<p><strong>Μωσῆς λέγει· ἐγὼ παραζηλώσω ὑμᾶς ἐπ᾽ οὐκ ἔθνει</strong> (Moses says: I will make you jealous over a non-nation) — <em>parazēloō</em> (G3863) from the Song of Moses (Deut 32:21); Paul identifies Moses as the <em>first</em> to predict Israel\'s jealousy over Gentile blessing. The <em>ep\' ouk ethnei</em> (over/by a non-nation) is the rhetorical inversion: a people not constituted as a nation receives what Israel did not.</p>',
    "20": '<p><strong>Ἠσαΐας δὲ ἀποτολμᾷ καὶ λέγει</strong> (but Isaiah speaks boldly/dares and says, G662) — <em>apotolmaō</em> is intensified boldness, almost recklessness; Paul notes that Isaiah\'s oracle is a remarkable claim. <strong>εὑρέθην τοῖς ἐμὲ μὴ ζητοῦσιν</strong> (I was found by those not seeking me) — aorist passive: the divine self-disclosure is described as God\'s activity, not human seeking.</p>',
    "21": '<p><strong>ὅλην τὴν ἡμέραν ἐξεπέτασα τὰς χεῖράς μου</strong> (all day long I spread out my hands, G1600) — the gesture of outstretched arms is simultaneously invitation (welcome) and appeal (to a reluctant person); the divine posture is persistent, active reaching-toward. <strong>πρὸς λαὸν ἀπειθοῦντα καὶ ἀντιλέγοντα</strong> (toward a disobedient and contradicting people, G544/G483) — <em>antilego</em> (to speak against/contradict) adds the verbal dimension of Israel\'s resistance: not merely behavioral disobedience but active verbal contradiction of God\'s word.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'romans')
    merge_comm(existing, ROMANS)
    save_comm('mkt-original', 'romans', existing)
    print('Romans 8–10 mkt-original written.')

if __name__ == '__main__':
    main()

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ROMANS = {
  "8": {
    "1": '<p><strong>οὐδὲν ἄρα νῦν κατάκριμα τοῖς ἐν Χριστῷ Ἰησοῦ</strong> (<em>ouden ara nyn katakrima tois en Christō Iēsou</em>) — "there is therefore now no condemnation for those in Christ Jesus." <em>Katakrima</em> (condemnation, the penalty/sentence itself) — distinct from <em>krima</em> (judgment); this is the executed sentence, not merely the verdict. <em>Nyn</em> (now) is temporally emphatic: the no-condemnation is present-tense reality, not merely future hope. <em>En Christō Iēsou</em> (in Christ Jesus) — the sphere of belonging; condemnation is abolished for those whose address is Christ, not for humanity in the abstract.</p>',
    "2": '<p><strong>ὁ γὰρ νόμος τοῦ πνεύματος τῆς ζωῆς ἐν Χριστῷ Ἰησοῦ</strong> (<em>ho gar nomos tou pneumatos tēs zōēs en Christō Iēsou</em>) — "for the law of the Spirit of life in Christ Jesus." <em>Nomos</em> here functions as "governing principle" or "operative power" rather than the Mosaic Torah; the Spirit operates with law-like regularity and authority. <strong>ἠλευθέρωσέν σε ἀπὸ τοῦ νόμου τῆς ἁμαρτίας καὶ τοῦ θανάτου</strong> — "has freed you from the law of sin and death" — the liberation is a completed act (aorist) that has achieved freedom; ch7 described the prison, ch8 announces the escape.</p>',
    "3": '<p><strong>τὸ γὰρ ἀδύνατον τοῦ νόμου</strong> (<em>to gar adynaton tou nomou</em>) — "for the impossibility of the law" — the law\'s inability is its incapacity to produce righteousness in the flesh-sphere (not a moral defect in the law itself, as 7:12 establishes). <strong>ἐν ὁμοιώματι σαρκὸς ἁμαρτίας</strong> (<em>en homoiōmati sarkos hamartias</em>) — "in the likeness of sinful flesh" — <em>homoiōma</em> (likeness, resemblance) is carefully chosen: Christ came in genuine human flesh but not identical with sinful flesh — the same shape but without the sin. <strong>καὶ περὶ ἁμαρτίας</strong> (<em>kai peri hamartias</em>) — "and concerning sin" or "as a sin offering" — <em>peri hamartias</em> is the LXX technical phrase for the sin offering (<em>asham/chattat</em>); Paul uses it ambiguously as both "regarding the problem of sin" and "as a sin offering to deal with sin." The double sense is intentional: Christ was sent both about-sin and as-sin-offering.</p>',
    "4": '<p><strong>τὸ δικαίωμα τοῦ νόμου πληρωθῇ ἐν ἡμῖν</strong> (<em>to dikaiōma tou nomou plērōthē en hēmin</em>) — "that the righteous requirement of the law might be fulfilled in us." <em>Dikaiōma</em> (the single righteous decree/requirement of the law, in the singular) — not all individual commandments but the law\'s one essential demand: the righteousness it requires. <em>Plērōthē</em> — aorist passive subjunctive: fulfilled by God acting in us, not by us fulfilling the law ourselves. <strong>τοῖς μὴ κατὰ σάρκα περιπατοῦσιν ἀλλὰ κατὰ πνεῦμα</strong> — "those not walking according to flesh but according to Spirit" — the present participle of <em>peripateō</em> (to walk about, to conduct one\'s life) describes the characteristic lifestyle orientation.</p>',
    "5": '<p><strong>οἱ γὰρ κατὰ σάρκα ὄντες τὰ τῆς σαρκὸς φρονοῦσιν</strong> (<em>hoi gar kata sarka ontes ta tēs sarkos phronousin</em>) — "for those who are according to the flesh set their minds on the things of the flesh." <em>Phroneō</em> (to think, have a mindset, set the mind toward) — more than cognition; it is the orientation of the whole person, the basic direction of desire and interest. The repeated use (vv5-8) establishes two fundamental directions of human existence: flesh-orientation and Spirit-orientation.</p>',
    "6": '<p><strong>τὸ γὰρ φρόνημα τῆς σαρκὸς θάνατος, τὸ δὲ φρόνημα τοῦ πνεύματος ζωὴ καὶ εἰρήνη</strong> (<em>to gar phronēma tēs sarkos thanatos, to de phronēma tou pneumatos zōē kai eirēnē</em>) — "for the mindset of the flesh is death, but the mindset of the Spirit is life and peace." <em>Phronēma</em> (mindset, the result of <em>phroneō</em>) — the noun crystallizes the orientation into its essential character. The antithesis is total: flesh-orientation terminates in death; Spirit-orientation produces life and shalom. The peace here is the same <em>eirēnē</em> as 5:1 — the restored relation with God that the Spirit-directed life enjoys.</p>',
    "7": '<p><strong>διότι τὸ φρόνημα τῆς σαρκὸς ἔχθρα εἰς θεόν</strong> (<em>dioti to phronēma tēs sarkos echthra eis theon</em>) — "because the mindset of the flesh is hostility toward God" — not merely indifferent to God but actively hostile (<em>echthra</em> = enmity, the state of being an enemy). <strong>τῷ γὰρ νόμῳ τοῦ θεοῦ οὐχ ὑποτάσσεται, οὐδὲ γὰρ δύναται</strong> — "for it does not submit to the law of God, nor is it able to" — the double impossibility: does not + cannot. The flesh is incapable of the submission the law requires; this is why law alone cannot produce righteousness.</p>',
    "8": '<p><strong>οἱ δὲ ἐν σαρκὶ ὄντες θεῷ ἀρέσαι οὐ δύνανται</strong> (<em>hoi de en sarki ontes theō aresai ou dynantai</em>) — "those who are in the flesh cannot please God." The <em>en sarki</em> (in the flesh) describes the sphere of existence, not the body per se; the pre-Spirit, Adam-shaped mode of being is incapable of the God-pleasing that constitutes righteousness. This incapacity grounds the necessity of the Spirit\'s work.</p>',
    "9": '<p><strong>ὑμεῖς δὲ οὐκ ἐστὲ ἐν σαρκὶ ἀλλ᾽ ἐν πνεύματι</strong> (<em>hymeis de ouk este en sarki all\' en pneumati</em>) — "but you are not in the flesh but in the Spirit" — present tense statement of sphere-transfer: the believer already inhabits the Spirit-sphere. <strong>εἴπερ πνεῦμα θεοῦ οἰκεῖ ἐν ὑμῖν</strong> — "if indeed the Spirit of God dwells in you" — the conditional <em>eiper</em> (if indeed, assuming that) is not an expression of doubt but a diagnostic: the Spirit\'s indwelling is the mark distinguishing believers from non-believers.</p>',
    "10": '<p><strong>εἰ δὲ Χριστὸς ἐν ὑμῖν, τὸ μὲν σῶμα νεκρὸν διὰ ἁμαρτίαν, τὸ δὲ πνεῦμα ζωὴ διὰ δικαιοσύνην</strong> — "but if Christ is in you, the body is dead because of sin, but the Spirit is life because of righteousness." The <em>sōma nekron</em> (body dead) — the mortal body under sentence of physical death due to the Adamic condition; but the <em>pneuma zōē</em> (spirit life) — the inner person already alive through the Spirit. The tension between the still-mortal body and the already-alive spirit anticipates vv11 and 23 (bodily resurrection).</p>',
    "11": '<p><strong>εἰ δὲ τὸ πνεῦμα τοῦ ἐγείραντος τὸν Ἰησοῦν ἐκ νεκρῶν οἰκεῖ ἐν ὑμῖν</strong> (<em>ei de to pneuma tou egeirantos ton Iēsoun ek nekrōn oikei en hymin</em>) — "but if the Spirit of the one who raised Jesus from the dead dwells in you." The participial description of God as "the one who raised Jesus" (aorist active participle) is theologically significant: the Spirit who indwells believers is identified by his resurrection-act; the same power that raised Jesus operates in the believer. <strong>ζωοποιήσει καὶ τὰ θνητὰ σώματα ὑμῶν</strong> — "will also give life to your mortal bodies" — the future resurrection of the physical body, not merely the spiritual component, is guaranteed by the same Spirit who now indwells.</p>',
    "12": '<p><strong>ὀφειλέται ἐσμέν, οὐ τῇ σαρκί</strong> (<em>opheiletai esmen, ou tē sarki</em>) — "we are debtors — not to the flesh." An <em>opheiletēs</em> (debtor, one who owes) is obligated to pay; Paul\'s point is that the flesh has no claim on the believer, no debt that must be paid by living according to its demands. The old obligation has been cancelled by death-with-Christ (ch6); the flesh is owed nothing.</p>',
    "13": '<p><strong>εἰ δὲ πνεύματι τὰς πράξεις τοῦ σώματος θανατοῦτε, ζήσεσθε</strong> (<em>ei de pneumati tas praxeis tou sōmatos thanatoute, zēsesthe</em>) — "but if by the Spirit you are putting to death the deeds of the body, you will live." <em>Thanatoute</em> (present active: you are putting to death, continually killing) — the ongoing discipline of mortification; not the body itself but its <em>praxeis</em> (deeds, actions). The instrument is the Spirit (<em>pneumati</em>, instrumental dative): the mortification is Spirit-empowered, not willpower alone.</p>',
    "14": '<p><strong>ὅσοι γὰρ πνεύματι θεοῦ ἄγονται, οὗτοι υἱοί εἰσιν θεοῦ</strong> (<em>hosoi gar pneumati theou agontai, houtoi huioi eisin theou</em>) — "for as many as are led by the Spirit of God, these are sons of God." <em>Agontai</em> (present passive: are being led, are being guided) — ongoing direction by the Spirit marks the <em>huioi theou</em> (sons/children of God). The sonship is defined not by ethnic descent but by Spirit-guidance, completing the redefinition of "who are the children of God" begun in ch4.</p>',
    "15": '<p><strong>πνεῦμα υἱοθεσίας</strong> (<em>pneuma huiothesias</em>) — "spirit of adoption" — <em>huiothesia</em> (adoption, son-placing) is Paul\'s unique term for the legal act by which outsiders are granted full family status. <strong>ἐν ᾧ κράζομεν· ἀββᾶ ὁ πατήρ</strong> (<em>en hō krazomen; abba ho pater</em>) — "in which we cry out: Abba, Father!" <em>Krazō</em> (to cry out, shout) — the word suggests intensity and spontaneity, not formal address. <em>Abba</em> is Aramaic (preserved from the earliest Christian liturgy, possibly from Jesus\'s own address in Gethsemane, Mark 14:36), followed immediately by the Greek translation <em>ho patēr</em> — a bilingual cry that shows the formula crossing Jewish-Gentile boundaries from the start.</p>',
    "16": '<p><strong>αὐτὸ τὸ πνεῦμα συμμαρτυρεῖ τῷ πνεύματι ἡμῶν</strong> (<em>auto to pneuma symmartryrei tō pneumati hēmōn</em>) — "the Spirit himself bears witness together with our spirit." <em>Symmartyreo</em> (to witness alongside, co-testify) — the Spirit\'s testimony is not separate from but conjoined with our own inner witness; the two witnesses together constitute the legal basis for confidence (cf. Deut 19:15, two witnesses). <em>Auto</em> (himself) is emphatic: the Spirit himself personally, not an impersonal force.</p>',
    "17": '<p><strong>κληρονόμοι μὲν θεοῦ, συγκληρονόμοι δὲ Χριστοῦ</strong> (<em>klēronomoi men theou, sygklēronomoi de Christou</em>) — "heirs of God and co-heirs with Christ." <em>Sygklēronomos</em> (co-heir, one who shares the inheritance lot with another) — the syn- prefix again: union with Christ means sharing his inheritance. <strong>εἴπερ συμπάσχομεν ἵνα καὶ συνδοξασθῶμεν</strong> — "if indeed we suffer with him so that we may also be glorified with him" — the co-suffering (sym-paschomen) is the path to co-glorification (syn-doxasthōmen); the pattern is Christ\'s own cross-to-resurrection trajectory.</p>',
    "18": '<p><strong>οὐκ ἄξια τὰ παθήματα τοῦ νῦν καιροῦ πρὸς τὴν μέλλουσαν δόξαν ἀποκαλυφθῆναι εἰς ἡμᾶς</strong> — "the sufferings of the present time are not worthy to be compared with the glory about to be revealed toward us." <em>Patheēmata tou nyn kairou</em> (sufferings of the present time-period) — the <em>kairos</em> (qualitatively significant time) of the age between resurrection and parousia. The comparison is qualitative, not quantitative: the sufferings are not merely outweighed but are categorically incomparable with the coming glory.</p>',
    "19": '<p><strong>ἡ γὰρ ἀποκαραδοκία τῆς κτίσεως τὴν ἀποκάλυψιν τῶν υἱῶν τοῦ θεοῦ ἀπεκδέχεται</strong> (<em>hē gar apokaradokia tēs ktiseōs tēn apokalypsin tōn huiōn tou theou apekdechetai</em>) — "for the eager expectation of creation is awaiting the revelation of the sons of God." <em>Apokaradokia</em> (craning forward of the head, eager watching-for) — a compound of <em>apo-kara-dokia</em>: the head (<em>kara</em>) stretched forward (<em>apo-</em>) in watching (<em>dokia</em>); an image of straining forward to see what is coming. Creation itself is personified as an eager watcher for the eschatological disclosure of God\'s children.</p>',
    "20": '<p><strong>τῇ γὰρ ματαιότητι ἡ κτίσις ὑπετάγη</strong> (<em>tē gar mataiotēti hē ktisis hypetageē</em>) — "for the creation was subjected to futility." <em>Mataiotēs</em> (futility, vanity, purposelessness) — the LXX term for <em>hebel</em> in Ecclesiastes (vapor, vanity); creation is subjected to a condition of frustrated meaninglessness. <strong>οὐχ ἑκοῦσα ἀλλὰ διὰ τὸν ὑποτάξαντα</strong> — "not willingly but because of the one who subjected it" — the passive and the participle of <em>hypotassō</em> (to subordinate) point to God\'s act at the fall; creation did not choose futility but received it through divine judgment (Gen 3:17-19).</p>',
    "21": '<p><strong>ἐλευθερωθήσεται ἀπὸ τῆς δουλείας τῆς φθορᾶς εἰς τὴν ἐλευθερίαν τῆς δόξης τῶν τέκνων τοῦ θεοῦ</strong> — "will be freed from the slavery of corruption into the freedom of the glory of the children of God." <em>Douleias tēs phthoras</em> (slavery of decay/corruption) — creation is enslaved to entropy and death; the eschatological freedom is freedom-from-decay, which is bodily resurrection extended to the cosmos itself.</p>',
    "22": '<p><strong>πᾶσα ἡ κτίσις συστενάζει καὶ συνωδίνει ἄχρι τοῦ νῦν</strong> (<em>pasa hē ktisis systenazei kai synōdinei achri tou nyn</em>) — "all creation groans together and labors together in birth pangs until now." Both verbs compound the <em>syn-</em> prefix: co-groaning and co-travailing. The birth-pain image (<em>ōdinō</em>) transforms suffering into purposeful labor: the pain is productive, pointing toward the new creation\'s birth. <em>Achri tou nyn</em> (until now) — ongoing up to the present moment.</p>',
    "23": '<p><strong>ἀπαρχὴν τοῦ πνεύματος ἔχοντες</strong> (<em>aparchēn tou pneumatos echontes</em>) — "having the firstfruits of the Spirit" — <em>aparchē</em> (firstfruits, the first-cut of the harvest) — the Spirit is the firstfruits, meaning: (a) the first installment of the coming eschatological life, and (b) the guarantee that the full harvest will follow. <strong>ἀπολύτρωσιν τοῦ σώματος</strong> (<em>apolytrōsin tou sōmatos</em>) — "redemption of the body" — not from the body (Gnostic) but of the body (resurrection); the Spirit\'s presence is the deposit (8:23; 2 Cor 1:22) securing the body\'s redemption.</p>',
    "24": '<p><strong>τῇ γὰρ ἐλπίδι ἐσώθημεν</strong> (<em>tē gar elpidi esōthēmen</em>) — "for in hope we were saved" — <em>esōthēmen</em> (aorist passive: we were saved) is past; but <em>elpidi</em> (in/by hope) qualifies what was received in the past as something whose completion remains future. Salvation\'s past-act (justification) aims toward a future-completion (glorification). <strong>ἐλπὶς δὲ βλεπομένη οὐκ ἔστιν ἐλπίς</strong> — "but hope that is seen is not hope" — a tautology that defines hope precisely by the non-visibility of its object.</p>',
    "25": '<p><strong>δι᾽ ὑπομονῆς ἀπεκδεχόμεθα</strong> (<em>di\' hypomonēs apekdechometha</em>) — "through endurance we wait eagerly" — <em>hypomonē</em> (endurance, remaining-under pressure) as the disposition required for hope; and <em>apekdechomai</em> (to await eagerly, to expect with outstretched neck — the same root as <em>apokaradokia</em> in v19) as the mode of the waiting. Patient eagerness is the paradox Paul describes.</p>',
    "26": '<p><strong>τὸ δὲ πνεῦμα συναντιλαμβάνεται τῇ ἀσθενείᾳ ἡμῶν</strong> (<em>to de pneuma synantilambanetai tē astheneiai hēmōn</em>) — "the Spirit helps us in our weakness" — <em>synantilambanetai</em> is a triple-compound verb: <em>syn-anti-lamban-</em> (together-against-taking) — the Spirit comes alongside and takes hold of the burden from the opposite side, sharing the carrying. <strong>ὑπερεντυγχάνει στεναγμοῖς ἀλαλήτοις</strong> (<em>hyperentynchanei stenagmois alalētois</em>) — "intercedes with groanings that cannot be uttered" — <em>hyperentynchanō</em> (to intercede on behalf of, with <em>hyper-</em> suggesting going beyond what we can do for ourselves); <em>alalētos</em> (speechless, beyond articulation) — the intercession is beyond human verbal capacity, not below it.</p>',
    "27": '<p><strong>ὁ δὲ ἐραυνῶν τὰς καρδίας οἶδεν τί τὸ φρόνημα τοῦ πνεύματος</strong> (<em>ho de eraunōn tas kardias oiden ti to phronēma tou pneumatos</em>) — "but the one who searches the hearts knows what the mindset of the Spirit is." God as the heart-searcher (OT: Ps 139:23; Jer 17:10) recognizes the Spirit\'s groanings as intelligible intercession, even though they exceed human language. The Spirit intercedes <em>kata theon</em> (according to God\'s will, literally "according to God") — perfectly aligned with divine purpose.</p>',
    "28": '<p><strong>πάντα συνεργεῖ εἰς ἀγαθόν</strong> (<em>panta synergei eis agathon</em>) — "all things work together for good." The textual variant: some manuscripts read "God works all things together for good" (<em>ho theos panta synergei eis agathon</em>); others read simply "all things work together." The former is grammatically harder and likely original. <strong>τοῖς κατὰ πρόθεσιν κλητοῖς οὖσιν</strong> (<em>tois kata prothesin klētois ousin</em>) — "to those who are called according to purpose" — <em>prothesis</em> (purpose, setting-before, deliberate plan) — God\'s eternal intention grounds the all-things-for-good promise; it is not a universal optimism but a promise specifically to the purposefully called.</p>',
    "29": '<p><strong>οὓς προέγνω, καὶ προώρισεν συμμόρφους τῆς εἰκόνος τοῦ υἱοῦ αὐτοῦ</strong> (<em>hous proegnō, kai proōrisen symmorphous tēs eikonos tou huiou autou</em>) — "those whom he foreknew he also predestined to be conformed to the image of his Son." <em>Proginōskō</em> (foreknow — more than mere prescience; in OT idiom, "to know" often means "to choose in covenantal love": Amos 3:2, Gen 18:19) — the divine foreknowing is the basis of the predestination, not merely its anticipation. <em>Symmorphous tēs eikonos</em> (conformed to the image) — the goal of predestination is Christlikeness: the restoration of the <em>eikōn</em> (image of God, Gen 1:26-27) through conformity to the Second Adam. <strong>πρωτότοκον ἐν πολλοῖς ἀδελφοῖς</strong> — "firstborn among many brothers" — Christ is the eldest son whose family the predestined share; the family resemblance is the theological point.</p>',
    "30": '<p><strong>οὓς δὲ προώρισεν, τούτους καὶ ἐκάλεσεν· καὶ οὓς ἐκάλεσεν, τούτους καὶ ἐδικαίωσεν· οὓς δὲ ἐδικαίωσεν, τούτους καὶ ἐδόξασεν</strong> — "those he predestined he also called; those he called he also justified; those he justified he also glorified." The golden chain: four aorists, all with the same subjects-become-objects structure. The striking feature is <em>edoxasen</em> (glorified — aorist): glorification is spoken of as past from the divine perspective, the completeness and certainty of the eschatological end making it grammatically past. The chain has no breaks: no one called is not justified; no one justified is not glorified.</p>',
    "31": '<p><strong>εἰ ὁ θεὸς ὑπὲρ ἡμῶν, τίς καθ᾽ ἡμῶν</strong> (<em>ei ho theos hyper hēmōn, tis kath\' hēmōn</em>) — "if God is for us, who is against us?" The rhetorical question opens the doxological crescendo of ch8. <em>Hyper hēmōn</em> (for us, on our behalf) — the spatial metaphor of God standing over/alongside in the defensive position. The answer to "who is against us?" is implicitly: no one who matters ultimately, given the God who is for us.</p>',
    "32": '<p><strong>ὅς γε τοῦ ἰδίου υἱοῦ οὐκ ἐφείσατο</strong> (<em>hos ge tou idiou huiou ouk epheisato</em>) — "who did not spare his own Son." <em>Epheisamto</em> is the aorist of <em>pheidomai</em> (to spare, withhold) — the same verb used in Gen 22:16 LXX when God says Abraham "did not spare" his son Isaac (<em>ouk epheisō tou huiou sou</em>). Paul\'s echo of the Aqedah is unmistakable: the Father does for Abraham\'s sake what Abraham was willing to do for God\'s sake. <em>Idiou</em> (his own, his very own) emphasizes the costliness of the gift. <strong>πῶς οὐχὶ καὶ σὺν αὐτῷ τὰ πάντα ἡμῖν χαρίσεται</strong> — "how will he not also with him freely give us all things?" — the a-fortiori: if God gave the greatest, he will give everything lesser as well.</p>',
    "33": '<p><strong>θεὸς ὁ δικαιῶν</strong> (<em>theos ho dikaiōn</em>) — "God who justifies" — the present active participle characterizes God as the one who continuously, habitually justifies. The rhetorical question <strong>τίς ἐγκαλέσει κατὰ ἐκλεκτῶν θεοῦ</strong> (who will bring a charge against God\'s elect?) echoes the Suffering Servant passage (Isa 50:8 LXX): the Servant can ask the same question. Paul applies the vindication-language to all who are in Christ.</p>',
    "34": '<p><strong>Χριστὸς Ἰησοῦς ὁ ἀποθανών, μᾶλλον δὲ ἐγερθείς, ὃς καί ἐστιν ἐν δεξιᾷ τοῦ θεοῦ</strong> — "Christ Jesus who died — more than that, who was raised — who also is at the right hand of God." Paul constructs the double a-fortiori: death → resurrection → session → intercession, each stage exceeding the previous in significance. <strong>ὃς καὶ ἐντυγχάνει ὑπὲρ ἡμῶν</strong> — "who also intercedes for us" — the present tense: the risen Christ is currently, continuously interceding (cf. Heb 7:25). The session at God\'s right hand (Ps 110:1) and the intercession combine to give the complete picture of Christ\'s heavenly priestly work.</p>',
    "35": '<p><strong>τίς ἡμᾶς χωρίσει ἀπὸ τῆς ἀγάπης τοῦ Χριστοῦ</strong> (<em>tis hēmas chōrisei apo tēs agapēs tou Christou</em>) — "who will separate us from the love of Christ?" <em>Chōrizō</em> (to separate, put apart) — the question asks about the agent and mechanism of potential separation. Paul\'s answer is a catalog (tribulation, distress, persecution, famine, nakedness, danger, sword) that represents precisely the suffering the Roman church was facing. These are not hypothetical threats.</p>',
    "36": '<p><strong>ἕνεκεν σοῦ θανατούμεθα ὅλην τὴν ἡμέραν</strong> (<em>heneken sou thanatoumetha holēn tēn hēmeran</em>) — "for your sake we are being put to death all day long" — citing Ps 44:22 LXX: the martyr-psalm applied to the experience of the Roman community. The present passive <em>thanatoumetha</em> (we are being killed) is ongoing; the daily death-experience of the early church is interpreted as participation in the Psalmist\'s suffering and by extension in Christ\'s death.</p>',
    "37": '<p><strong>ἀλλ᾽ ἐν τούτοις πᾶσιν ὑπερνικῶμεν</strong> (<em>all\' en toutois pasin hypernikōmen</em>) — "but in all these things we more-than-conquer." <em>Hypernikaō</em> (to super-conquer, to more-than-win) — a verb Paul apparently coined; the <em>hyper-</em> prefix intensifies beyond ordinary victory. The victory is won not by escaping the sufferings but <em>in</em> them (<em>en toutois</em>). <strong>διὰ τοῦ ἀγαπήσαντος ἡμᾶς</strong> — "through the one who loved us" — the aorist participle <em>agapēsantos</em> (having loved) points to the cross-event as the past act that grounds the present victory.</p>',
    "38": '<p><strong>πέπεισμαι γὰρ ὅτι οὔτε θάνατος οὔτε ζωή</strong> (<em>pepeismai gar hoti oute thanatos oute zōē</em>) — "for I am convinced that neither death nor life" — <em>pepeismai</em> (perfect passive: I have been convinced and remain convinced) — not mere intellectual assent but settled persuasion. The catalog that follows covers every conceivable dimension of reality that might threaten the love-bond: death, life, angels, rulers, present things, future things, powers, height, depth, any other created thing.</p>',
    "39": '<p><strong>οὔτε τις κτίσις ἑτέρα δυνήσεται ἡμᾶς χωρίσαι ἀπὸ τῆς ἀγάπης τοῦ θεοῦ τῆς ἐν Χριστῷ Ἰησοῦ τῷ κυρίῳ ἡμῶν</strong> — "nor any other created thing will be able to separate us from the love of God that is in Christ Jesus our Lord." The <em>ktisei heterai</em> (any other created thing) catches everything not previously listed; the catalog is meant to be exhaustive. The love of God is located <em>en Christō Iēsou tō kyriō hēmōn</em> — the love is not an abstraction but has a specific address: it is the love enacted in and through Christ Jesus who is Lord. The chapter that began with "no condemnation" ends with "no separation."</p>'
  },
  "9": {
    "1": '<p><strong>ἀλήθειαν λέγω ἐν Χριστῷ, οὐ ψεύδομαι</strong> (<em>alētheian legō en Christō, ou pseudomai</em>) — "I am speaking truth in Christ, I am not lying." The triple attestation (truth + in Christ + not lying + conscience through the Holy Spirit) is striking; Paul feels the need for unusual emphasis before a statement he knows will surprise his readers. <em>En Christō</em> grounds his truthfulness in the sphere of Christ rather than merely in personal integrity.</p>',
    "2": '<p><strong>λύπη μοί ἐστιν μεγάλη καὶ ἀδιάλειπτος ὀδύνη τῇ καρδίᾳ μου</strong> — "I have great grief and unceasing anguish in my heart." <em>Odynoē</em> (anguish, sharp pain) — the word used of the father\'s grief in Luke 2:48 and 16:24; intense, physical-emotional pain. <em>Adialeiptos</em> (without interruption, ceaseless) — Paul\'s grief for Israel is not occasional but constant. This emotional register prepares for the theological argument of chs9-11: the argument is not academic but pastoral and personal.</p>',
    "3": '<p><strong>ηὐχόμην γὰρ ἀνάθεμα εἶναι αὐτὸς ἐγὼ ἀπὸ τοῦ Χριστοῦ ὑπὲρ τῶν ἀδελφῶν μου</strong> — "for I could pray to be accursed from Christ myself, for the sake of my brothers." <em>Anathema</em> (devoted to destruction, placed under curse, excommunicated from the community) — the most extreme negative status; Paul uses the imperfect <em>ēuchomēn</em> (I was wishing/praying) to indicate a counterfactual wish: he would pray for this if it were possible. The echo of Moses\'s prayer (Exod 32:32) and the paradox of wishing separation from Christ for the sake of his kinfolk is the strongest expression of corporate solidarity in Paul.</p>',
    "4": '<p><strong>Ἰσραηλῖται ὧν ἡ υἱοθεσία καὶ ἡ δόξα καὶ αἱ διαθῆκαι καὶ ἡ νομοθεσία καὶ ἡ λατρεία καὶ αἱ ἐπαγγελίαι</strong> — "Israelites, who have the adoption and the glory and the covenants and the law-giving and the worship and the promises." The six-part catalog of Israel\'s privileges is theologically dense: <em>huiothesia</em> (adoption — national sonship, Exod 4:22), <em>doxa</em> (the Shekinah glory), <em>diathēkai</em> (covenants — plural, covering all the Abrahamic, Mosaic, Davidic, and new covenant), <em>nomothesia</em> (the giving of the Torah), <em>latreia</em> (temple worship/service), <em>epangeliai</em> (the promises of God). These are real gifts — Paul does not retract them.</p>',
    "5": '<p><strong>ὁ ὢν ἐπὶ πάντων θεὸς εὐλογητὸς εἰς τοὺς αἰῶνας</strong> (<em>ho ōn epi pantōn theos eulogētos eis tous aiōnas</em>) — "the one who is over all, God blessed forever." This is one of the most debated christological texts in Paul: whether the doxology refers to Christ (making it an explicit divine predication of Christ) or to God the Father. The syntax most naturally reads "Christ... who is God over all, blessed forever" — a direct attribution of divinity to Christ. The present participle <em>ho ōn</em> (the one being) echoes the divine name and Exod 3:14 LXX.</p>',
    "6": '<p><strong>οὐχ οἷον δὲ ὅτι ἐκπέπτωκεν ὁ λόγος τοῦ θεοῦ</strong> (<em>ouch hoion de hoti ekpeptōken ho logos tou theou</em>) — "but it is not as though the word of God has failed." <em>Ekpiptō</em> (to fall out, fail, miscarry) — perfect tense: the word has not fallen and has not remained fallen. <strong>οὐ γὰρ πάντες οἱ ἐξ Ἰσραὴλ οὗτοι Ἰσραήλ</strong> — "for not all those from Israel are Israel" — the crucial distinction between ethnic-national Israel and the Israel defined by promise and faith; Paul\'s argument is not that God\'s word failed but that God\'s Israel was always defined by election, not by birth.</p>',
    "7": '<p><strong>οὐδ᾽ ὅτι εἰσὶν σπέρμα Ἀβραάμ, πάντες τέκνα</strong> (<em>oud\' hoti eisin sperma Abraam, pantes tekna</em>) — "nor because they are Abraham\'s seed are they all children." Citing Gen 21:12: <em>en Isaak klēthēsetai soi sperma</em> (in Isaac shall your seed be called). The selection of Isaac over Ishmael establishes the principle that physical descent from Abraham does not automatically constitute being the seed of the promise; the divine election chooses which physical line carries the promise.</p>',
    "8": '<p><strong>τὰ τέκνα τῆς σαρκός, ταῦτα οὐ τέκνα τοῦ θεοῦ, ἀλλὰ τὰ τέκνα τῆς ἐπαγγελίας λογίζεται εἰς σπέρμα</strong> — "the children of the flesh, these are not the children of God; but the children of the promise are counted as the seed." The antithesis <em>tekna tēs sarkos / tekna tēs epangelias</em> (children of the flesh / children of the promise) directly parallels the Isaac/Ishmael distinction. The <em>logizetai</em> (reckoned/counted) returns the imputation-language of ch4 to the question of who constitutes God\'s people.</p>',
    "9": '<p><strong>κατὰ τὸν καιρὸν τοῦτον ἐλεύσομαι καὶ ἔσται τῇ Σάρρᾳ υἱός</strong> — "at this time I will come and Sarah will have a son" — citing Gen 18:10, 14 (LXX); the divine promise that constituted Isaac as the child of promise rather than human arrangement or natural capacity. The basis of Isaac\'s birth is the divine word, not Sarah\'s biology.</p>',
    "10": '<p><strong>Ῥεβέκκα ἐξ ἑνὸς κοίτην ἔχουσα</strong> — "Rebecca also having conceived by one man" — the Rebecca-Esau-Jacob case sharpens the election argument: not only is the promise not through Ishmael (Hagar\'s son by another relationship) but even within the same womb, the same father, the same moment of conception, God chose Jacob over Esau before birth.</p>',
    "11": '<p><strong>μήπω γὰρ γεννηθέντων μηδὲ πραξάντων τι ἀγαθὸν ἢ φαῦλον</strong> — "for not yet having been born or having done anything good or bad." The pre-birth timing is Paul\'s main point: the election was declared before any moral basis existed, eliminating works as the ground of election. <strong>ἡ κατ᾽ ἐκλογὴν πρόθεσις τοῦ θεοῦ μένῃ</strong> (<em>hē kat\' eklogēn prothesis tou theou menē</em>) — "that the purpose of God according to election might stand" — <em>eklogē</em> (election, the act of choosing) as the governing principle of the divine purpose, not human effort.</p>',
    "12": '<p><strong>ὁ μείζων δουλεύσει τῷ ἐλάσσονι</strong> (<em>ho meizōn douleusei tō elassoni</em>) — "the elder will serve the younger" — citing Gen 25:23: the reversal of birth-order priority as the expression of divine election that operates contrary to human convention. The oracle is about the nations (Israel and Edom) descending from the twins, not merely individual destinies.</p>',
    "13": '<p><strong>τὸν Ἰακὼβ ἠγάπησα, τὸν δὲ Ἠσαῦ ἐμίσησα</strong> (<em>ton Iakōb ēgapēsa, ton de Ēsau emisēsa</em>) — "Jacob I loved, but Esau I hated" — citing Mal 1:2-3, written approximately 1,500 years after the birth of Jacob and Esau; the text speaks nationally (Israel vs. Edom), not individually. <em>Miseo</em> (to hate) in the Semitic idiom means "to love less" (cf. Luke 14:26 / Matt 10:37 — hate father vs. love less); in Malachi the referent is God\'s preferential covenantal love for Israel-Jacob over Edom-Esau.</p>',
    "14": '<p><strong>μὴ ἀδικία παρὰ τῷ θεῷ</strong> (<em>mē adikia para tō theō</em>) — "is there unrighteousness with God?" — <em>adikia</em> (injustice, unrighteousness) is the charge Paul anticipates: if God chose Jacob over Esau before birth, is he unjust? The <em>mē genoito</em> refuses the charge; the argument from Exodus follows.</p>',
    "15": '<p><strong>ἐλεήσω ὃν ἂν ἐλεῶ καὶ οἰκτιρήσω ὃν ἂν οἰκτίρω</strong> (<em>eleēsō hon an eleō kai oiktirēsō hon an oiktirō</em>) — "I will have mercy on whom I have mercy, and I will have compassion on whom I have compassion" — citing Exod 33:19 (Moses\'s encounter with divine glory). The tautological structure is deliberate: God\'s mercy is grounded in God\'s mercy, not in the recipient\'s worthiness. <em>Eleeō</em> (to show mercy) and <em>oiktirō</em> (to have compassion) — both verbs express gracious response to need rather than response to desert.</p>',
    "16": '<p><strong>οὐ τοῦ θέλοντος οὐδὲ τοῦ τρέχοντος ἀλλὰ τοῦ ἐλεῶντος θεοῦ</strong> (<em>ou tou thelontos oude tou trechontos alla tou eleōntos theou</em>) — "not of the one who wills nor of the one who runs, but of the God who has mercy." The athletic metaphor (<em>trechō</em> = to run a race) represents maximum human effort; both will and effort are excluded as grounds of the divine mercy. The mercy depends entirely on the Mercy-giver.</p>',
    "17": '<p><strong>εἰς αὐτὸ τοῦτο ἐξήγειρά σε ὅπως ἐνδείξωμαι ἐν σοὶ τὴν δύναμίν μου</strong> — "for this very purpose I raised you up, so that I might demonstrate my power in you" — citing Exod 9:16 (the Pharaoh hardening section). <em>Exegeirō</em> (to raise up, bring onto the stage) — God placed Pharaoh in history for the purpose of making divine power visible. The <em>eis auto touto</em> (for this very purpose) is emphatic: Pharaoh\'s historical role is purposeful, not accidental.</p>',
    "18": '<p><strong>ὃν δὲ θέλει σκληρύνει</strong> (<em>hon de thelei sklēryni</em>) — "but whom he wills he hardens." <em>Sklēryno</em> (to harden, make rigid) — the hardening of Pharaoh is here attributed to divine action; but the Exodus narrative also attributes it to Pharaoh\'s own heart-hardening (Exod 8:15, 32; 9:34) and to divine hardening (Exod 9:12; 10:1, 20, 27; 11:10). Paul is working with the final state of the narrative\'s complex portrayal: God\'s sovereign act works through and with Pharaoh\'s own willing rebellion.</p>',
    "19": '<p><strong>τῷ γὰρ βουλήματι αὐτοῦ τίς ἀνθέστηκεν</strong> (<em>tō gar boulēmati autou tis anthistēken</em>) — "for who has resisted his will?" <em>Boulēma</em> (deliberate will, determined intention) — the strongest Greek word for will; the perfect <em>anthistēken</em> (has stood-against and succeeded) implies that no one has successfully resisted. Paul states the objection rather than dismissing it; the questioner is not wrong about divine sovereignty but wrong about what that implies for divine justice.</p>',
    "20": '<p><strong>μενοῦνγε ὦ ἄνθρωπε, σύ τίς εἶ ὁ ἀνταποκρινόμενος τῷ θεῷ</strong> (<em>menounge ō anthrōpe, sy tis ei ho antapokrinoamenos tō theō</em>) — "on the contrary, O human, who are you to answer back to God?" <em>Menounge</em> (on the contrary, rather) — a strong adversative. <em>Antapokrinomai</em> (to answer back, argue against, talk back) — the word suggests presumptuous contradiction. <strong>μὴ ἐρεῖ τὸ πλάσμα τῷ πλάσαντι</strong> — "will the thing formed say to the one who formed it?" — the pottery/potter image from Isa 29:16 and 45:9 (cf. Jer 18): the creature has no standing to interrogate the Creator\'s choices regarding the creature.</p>',
    "21": '<p><strong>ἐξουσίαν ἐπὶ τοῦ πηλοῦ</strong> (<em>exousian epi tou pēlou</em>) — "authority over the clay" — <em>pēlos</em> (clay, mud) and <em>phyrō</em> (to mix, knead) — the potter holds full authority over the same lump of clay to make both honorable and dishonorable vessels. Paul\'s point: God\'s right over his creatures is analogous to the potter\'s right over clay — not that humans are inert material but that God\'s sovereign prerogative over creation is unquestionable.</p>',
    "22": '<p><strong>σκεύη ὀργῆς κατηρτισμένα εἰς ἀπώλειαν</strong> (<em>skeuē orgēs katērtismena eis apōleian</em>) — "vessels of wrath prepared for destruction." <em>Katartizō</em> (to prepare, equip, mend) — the passive voice here is significant: the vessels were prepared (possibly self-prepared through persistent rebellion, or possibly divinely appointed). The passive is ambiguous, contrasting with the active <em>proētoimasen</em> (he prepared beforehand) in v23 — God explicitly prepared the mercy-vessels; the wrath-vessels are simply described as prepared. <em>Apōleia</em> (destruction, loss, perishing).</p>',
    "23": '<p><strong>σκεύη ἐλέους ἃ προητοίμασεν εἰς δόξαν</strong> (<em>skeuē eleous ha proētoimasen eis doxan</em>) — "vessels of mercy which he prepared beforehand for glory." The active <em>proētoimasen</em> (he prepared in advance) applied to the mercy-vessels emphasizes God\'s prior gracious intention; the vessels of glory are the products of divine prevenient mercy, not of their own preparation.</p>',
    "24": '<p><strong>οὓς καὶ ἐκάλεσεν ἡμᾶς οὐ μόνον ἐξ Ἰουδαίων ἀλλὰ καὶ ἐξ ἐθνῶν</strong> — "whom he also called us, not only from Jews but also from Gentiles." The identification of the "us" — the vessels of mercy — includes both Jewish and Gentile believers; the Hosea and Isaiah quotations that follow substantiate the Gentile inclusion and the Jewish remnant theology from Scripture itself.</p>',
    "25": '<p><strong>καλέσω τὸν οὐ λαόν μου λαόν μου</strong> (<em>kalesō ton ou laon mou laon mou</em>) — citing Hos 2:23: "I will call those who were not my people, my people." Hosea\'s original context was Israel\'s restoration after exile; Paul applies it to the Gentile calling, a bold rereading that finds in Israel\'s restoration-promise a pattern for the wider inclusion. The hermeneutical move: the restoration of Not-My-People to My-People is a pattern that can include those who were never My-People at all.</p>',
    "26": '<p><strong>ἐκεῖ κληθήσονται υἱοὶ θεοῦ ζῶντος</strong> (<em>ekei klēthēsontai huioi theou zōntos</em>) — "there they will be called sons of the living God" — citing Hos 1:10. The shift from <em>ou laos mou</em> (not my people) to <em>huioi theou</em> (sons of God) is an elevation beyond mere restoration to covenantal membership; those who were non-people become children of God. Paul finds Gentile sonship in the OT prophetic pattern.</p>',
    "27": '<p><strong>τὸ ὑπόλειμμα σωθήσεται</strong> (<em>to hypoleimma sōthēsetai</em>) — "the remnant will be saved" — citing Isa 10:22-23 LXX. <em>Hypoleimma</em> (remnant, what remains after a cutting-down) — the minority that survives the judgment. Isaiah\'s point was that despite Israel\'s numerical vastness, only a remnant would return; Paul reads this as the pattern for his own time: even though ethnic Israel as a whole has not believed, there is a remnant (see 11:1-7).</p>',
    "28": '<p><strong>λόγον γὰρ συντελῶν καὶ συντέμνων ποιήσει κύριος ἐπὶ τῆς γῆς</strong> — "for the Lord will carry out his word on the earth, completing it and cutting it short" — the <em>logos syntelōn kai syntemnōn</em> (word completing and cutting short) images the divine judgment as swift and comprehensive: God executes his purposes without delay or remainder.</p>',
    "29": '<p><strong>εἰ μὴ κύριος σαβαὼθ ἐγκατέλιπεν ἡμῖν σπέρμα</strong> (<em>ei mē kyrios sabaōth egkatelipen hēmin sperma</em>) — "unless the Lord of Sabaoth had left us a seed" — citing Isa 1:9. <em>Kyrios Sabaōth</em> (Lord of Hosts/Armies — the title preserved in transliteration) is Paul\'s only use of this divine name in his letters; the LXX transliteration preserves the Hebrew military title. The "seed" left is the remnant, without which Israel would have become Sodom and Gomorrah — utterly destroyed.</p>',
    "30": '<p><strong>ἔθνη τὰ μὴ διώκοντα δικαιοσύνην κατέλαβεν δικαιοσύνην</strong> (<em>ethnē ta mē diōkonta dikaiosynēn katelaben dikaiosynēn</em>) — "Gentiles who were not pursuing righteousness obtained righteousness." <em>Diōkō</em> (to pursue, chase, hunt) — the athletic image of zealous pursuit; the Gentiles were not even running the righteousness-race, yet they obtained what the runners missed. <em>Katalambanō</em> (to lay hold of, obtain, grasp) — they grasped righteousness; the emphasis is on the unexpected, undeserved, un-pursued nature of the reception.</p>',
    "31": '<p><strong>Ἰσραὴλ δὲ διώκων νόμον δικαιοσύνης εἰς νόμον οὐκ ἔφθασεν</strong> (<em>Israēl de diōkōn nomon dikaiosynēs eis nomon ouk ephthasen</em>) — "but Israel, pursuing a law of righteousness, did not arrive at the law." The ironic reversal: those who were earnestly pursuing the law-righteousness did not reach it, while those not pursuing received righteousness by faith. <em>Phthanō</em> (to arrive at, attain, precede) — Israel did not arrive at the goal of the very law they were running toward.</p>',
    "32": '<p><strong>διότι οὐκ ἐκ πίστεως ἀλλ᾽ ὡς ἐξ ἔργων</strong> (<em>dioti ouk ek pisteōs all\' hōs ex ergōn</em>) — "because not by faith but as if by works" — the diagnois: Israel\'s error was not insufficient zeal but misdiagnosis of the mechanism — treating righteousness as a works-achievement rather than a faith-reception. <strong>προσέκοψαν τῷ λίθῳ τοῦ προσκόμματος</strong> — "they stumbled over the stone of stumbling" — citing Isa 8:14: the stone that was meant to be a sanctuary became a stumbling block for those who refused the divine invitation.</p>',
    "33": '<p><strong>Ἰδοὺ τίθημι ἐν Σιὼν λίθον προσκόμματος καὶ πέτραν σκανδάλου</strong> — "Behold I am laying in Zion a stone of stumbling and a rock of offense" — a composite citation of Isa 28:16 and Isa 8:14. The paradox: God deliberately placed the stone (Christ) in Zion (the center of Israel\'s religion) where it would be either the cornerstone of salvation or the stumbling block of offense. <strong>ὁ πιστεύων ἐπ᾽ αὐτῷ οὐ καταισχυνθήσεται</strong> — "the one who believes upon him will not be put to shame" — the stone that causes stumbling for unbelief is the foundation of confidence for faith.</p>'
  },
  "10": {
    "1": '<p><strong>ἡ μὲν εὐδοκία τῆς ἐμῆς καρδίας καὶ ἡ δέησις πρὸς τὸν θεὸν ὑπὲρ αὐτῶν εἰς σωτηρίαν</strong> — "my heart\'s desire and prayer to God for them is for salvation." <em>Eudokia</em> (good-pleasure, heartfelt desire, earnest wish) — the same word used for God\'s good pleasure and for human deep longing. Paul\'s prayer (<em>deēsis</em> = supplication, petition) for Israel\'s salvation frames the theological analysis that follows: the argument comes from love, not from polemical distancing.</p>',
    "2": '<p><strong>ζῆλον θεοῦ ἔχουσιν ἀλλ᾽ οὐ κατ᾽ ἐπίγνωσιν</strong> (<em>zēlon theou echousin all\' ou kat\' epignōsin</em>) — "they have a zeal for God but not according to full knowledge." Paul bears witness to the genuineness of Israel\'s zeal (<em>zēlos</em> = ardent devotion, passionate commitment) before diagnosing its deficiency. <em>Epignōsis</em> (accurate, full knowledge) as opposed to mere <em>gnōsis</em> (knowledge) — the problem is not absence of religious knowledge but the specific lack of recognizing Christ as the goal of the law they zealously pursued.</p>',
    "3": '<p><strong>τὴν ἰδίαν δικαιοσύνην ζητοῦντες στῆσαι, τῇ δικαιοσύνῃ τοῦ θεοῦ οὐχ ὑπετάγησαν</strong> (<em>tēn idian dikaiosynēn zētountes stēsai, tē dikaiosynē tou theou ouch hypetageēsan</em>) — "seeking to establish their own righteousness, they did not submit to the righteousness of God." <em>Tēn idian dikaiosynēn</em> (their own righteousness) — not necessarily self-righteousness in the modern psychological sense but the righteousness of Torah-observance as the community marker. <em>Stēsai</em> (to establish, set up, make stand) — the attempt to make it stand on its own footing. The failure is refusal of submission (<em>hypotassō</em>) to what God offers.</p>',
    "4": '<p><strong>τέλος γὰρ νόμου Χριστός</strong> (<em>telos gar nomou Christos</em>) — "for Christ is the <em>telos</em> of the law." The most exegetically debated verse in chs9-11: <em>telos</em> can mean (a) end (termination — Christ ends the law\'s reign), (b) goal/fulfillment (Christ is what the law was pointing toward), or (c) both simultaneously. The OT-fulfillment language throughout Romans and the positive view of the law (7:12, 8:4) support the goal/fulfillment reading, though the cessation of the law as the mechanism of justification is also real. <strong>εἰς δικαιοσύνην παντὶ τῷ πιστεύοντι</strong> — "for righteousness to everyone who believes" — the universal scope is the point: Christ as telos of the law means the righteousness the law pointed toward is now available to all believers, not just those under Torah.</p>',
    "5": '<p><strong>ὁ ποιήσας αὐτὰ ἄνθρωπος ζήσεται ἐν αὐτοῖς</strong> (<em>ho poiēsas auta anthrōpos zēsetai en autois</em>) — citing Lev 18:5: "the person who does these things will live by them." The law-righteousness is defined by doing; its promise is life contingent on complete performance. Paul cites this not to condemn the law but to contrast the operative principle of law-righteousness (doing-and-living) with faith-righteousness (receiving-and-living).</p>',
    "6": '<p><strong>ἡ δὲ ἐκ πίστεως δικαιοσύνη οὕτως λέγει</strong> (<em>hē de ek pisteōs dikaiosynē houtōs legei</em>) — "but the righteousness from faith speaks thus." Paul personifies faith-righteousness as a speaking entity and then has it speak Deut 30:12-14. The Christological re-reading of Deuteronomy: Moses\'s word about the accessibility of Torah-keeping is applied to the accessibility of Christ. <strong>μὴ εἴπῃς ἐν τῇ καρδίᾳ σου· τίς ἀναβήσεται εἰς τὸν οὐρανόν</strong> — "do not say in your heart: who will ascend into heaven?" — Deut 30:12 asked who would ascend to bring the commandment down; Paul reads it as asking who would ascend to bring Christ down (as if the Incarnation needed to be achieved by human effort).</p>',
    "7": '<p><strong>ἢ τίς καταβήσεται εἰς τὴν ἄβυσσον</strong> (<em>ē tis katabēsetai eis tēn abysson</em>) — "or who will descend into the abyss?" Deut 30:13 asked who would cross the sea to bring the commandment; Paul reads the sea as the <em>abyssos</em> (the deep, the underworld) and applies it to descending to bring Christ up from the dead (as if the resurrection needed to be achieved by human effort). The point: both Incarnation and Resurrection are divine acts already accomplished; faith does not need to achieve them but to receive them.</p>',
    "8": '<p><strong>ἐγγύς σου τὸ ῥῆμά ἐστιν, ἐν τῷ στόματί σου καὶ ἐν τῇ καρδίᾳ σου</strong> (<em>engys sou to rhēma estin, en tō stomati sou kai en tē kardia sou</em>) — "the word is near you, in your mouth and in your heart" — Deut 30:14 LXX. The accessibility of the word is the key: the faith-word (<em>rhēma</em>) about Christ is already near, not distant and unreachable. <strong>τοῦτ᾽ ἔστιν τὸ ῥῆμα τῆς πίστεως ὃ κηρύσσομεν</strong> — "that is, the word of faith that we are proclaiming" — Paul identifies his gospel-proclamation as the near word that Deuteronomy predicted.</p>',
    "9": '<p><strong>ὅτι ἐὰν ὁμολογήσῃς ἐν τῷ στόματί σου κύριον Ἰησοῦν</strong> (<em>hoti ean homologēsēs en tō stomati sou kyrion Iēsoun</em>) — "that if you confess with your mouth Jesus as Lord." <em>Homologeō</em> (to say the same thing, confess, declare openly) — the confession is public, vocal, the mouth-component of the Deut 30 word-in-the-mouth. <em>Kyrion Iēsoun</em> — the predicate nominative makes "Lord" the declaration about Jesus; this is early creedal formula: <em>Iēsous kyrios</em> (Jesus is Lord). <strong>καὶ πιστεύσῃς ἐν τῇ καρδίᾳ σου ὅτι ὁ θεὸς αὐτὸν ἤγειρεν ἐκ νεκρῶν</strong> — "and believe in your heart that God raised him from the dead" — the heart-content of faith is specifically the resurrection; resurrection-faith is the heart-component of the Deut 30 word-in-the-heart.</p>',
    "10": '<p><strong>καρδίᾳ γὰρ πιστεύεται εἰς δικαιοσύνην, στόματι δὲ ὁμολογεῖται εἰς σωτηρίαν</strong> (<em>kardia gar pisteuetai eis dikaiosynēn, stomati de homologeitai eis sōtērian</em>) — "for with the heart one believes for righteousness, and with the mouth one confesses for salvation." The present passives are impersonal generalities: believing and confessing are the standard operations of salvific reception. The heart-mouth structure from Deut 30 maps onto the faith-confession structure of the gospel.</p>',
    "11": '<p><strong>πᾶς ὁ πιστεύων ἐπ᾽ αὐτῷ οὐ καταισχυνθήσεται</strong> (<em>pas ho pisteuōn ep\' autō ou kataischynthēsetai</em>) — "everyone who believes in him will not be put to shame" — re-citing Isa 28:16 (first cited at 9:33). The emphasis now is on <em>pas</em> (everyone/all) — the universality of the promise: no distinction of Jew or Greek in the scope of the faith-promise.</p>',
    "12": '<p><strong>οὐ γάρ ἐστιν διαστολὴ Ἰουδαίου τε καὶ Ἕλληνος</strong> (<em>ou gar estin diastolē Ioudaiou te kai Hellēnos</em>) — "for there is no distinction between Jew and Greek." <em>Diastolē</em> (distinction, difference, separation) — the same word used in 3:22. The no-distinction cuts both ways: both need salvation, both can receive it by the same mechanism. <strong>ὁ γὰρ αὐτὸς κύριος πάντων</strong> — "for the same Lord is Lord of all" — one Lord over all eliminates ethnic-religious distinctions in access to divine blessing.</p>',
    "13": '<p><strong>πᾶς γὰρ ὃς ἂν ἐπικαλέσηται τὸ ὄνομα κυρίου σωθήσεται</strong> (<em>pas gar hos an epikalesētai to onoma kyriou sōthēsetai</em>) — "for everyone who calls upon the name of the Lord will be saved" — citing Joel 2:32 (3:5 MT). In Joel <em>kyrios</em> is YHWH; Paul applies it to Christ without explanation, assuming that Christ shares the divine name and identity. The <em>epikalesētai</em> (calling upon) is the corporate prayer and invocation that summarizes the mouth-confession of v9.</p>',
    "14": '<p><strong>πῶς οὖν ἐπικαλέσωνται εἰς ὃν οὐκ ἐπίστευσαν</strong> — "how then shall they call upon one in whom they have not believed?" The evangelistic logic-chain begins: calling requires believing; believing requires hearing; hearing requires proclamation; proclamation requires being sent. The chain is retrogressive, moving from the final act back to the initiating commission.</p>',
    "15": '<p><strong>ὡς ὡραῖοι οἱ πόδες τῶν εὐαγγελιζομένων τὰ ἀγαθά</strong> (<em>hōs hōraioi hoi podes tōn euangelizomenōn ta agatha</em>) — "how beautiful are the feet of those who proclaim good news" — citing Isa 52:7. <em>Hōraios</em> (beautiful, timely, of the right season) — the feet of the messenger bringing good news are beautiful because of their message, not their form; <em>euangelizō</em> (to proclaim good news) is both the verb behind "gospel" (<em>euangelion</em>) and the action of the herald whose feet Isaiah celebrates. Paul identifies the Christian mission as the fulfillment of Isaiah\'s eschatological herald.</p>',
    "16": '<p><strong>κύριε, τίς ἐπίστευσεν τῇ ἀκοῇ ἡμῶν</strong> (<em>kyrie, tis episteusen tē akoē hēmōn</em>) — "Lord, who has believed our message?" — citing Isa 53:1 LXX. <em>Akoē</em> (hearing, report, what is heard) — the Servant\'s message was rejected; Paul uses this as scriptural precedent for the unbelief of many in Israel. The hearing-but-not-believing confirms that the failure is not in the proclamation but in the response.</p>',
    "17": '<p><strong>ἄρα ἡ πίστις ἐξ ἀκοῆς, ἡ δὲ ἀκοὴ διὰ ῥήματος Χριστοῦ</strong> (<em>ara hē pistis ex akoēs, hē de akoē dia rhēmatos Christou</em>) — "so faith comes from hearing, and hearing through the word of Christ." The summary conclusion: the chain is: word of Christ → proclamation → hearing → faith → calling → salvation. <em>Rhēma Christou</em> (word of Christ) — either the word about Christ (objective genitive: the gospel about him) or the word Christ speaks (subjective genitive); both readings are theologically valid.</p>',
    "18": '<p><strong>εἰς πᾶσαν τὴν γῆν ἐξῆλθεν ὁ φθόγγος αὐτῶν</strong> (<em>eis pasan tēn gēn exēlthen ho phthongos autōn</em>) — "their voice has gone out into all the earth" — citing Ps 19:4 LXX. <em>Phthongos</em> (sound, voice, tone) — the Psalm described the wordless speech of the heavens declaring God\'s glory; Paul applies this cosmic proclamation to the missionaries whose message has gone to all nations. The citation answers the question "have they not heard?" — yes, the proclamation has gone everywhere.</p>',
    "19": '<p><strong>ἐγὼ παραζηλώσω ὑμᾶς ἐπ᾽ οὐκ ἔθνει</strong> (<em>egō parazēlōsō hymas ep\' ouk ethnei</em>) — "I will make you jealous with those who are not a nation" — citing Deut 32:21. <em>Parazēloō</em> (to make jealous by means of something near/alongside) — the Song of Moses predicted that God would use a non-nation to provoke Israel\'s jealousy; Paul reads this as the Gentile mission\'s role in Israel\'s salvation story (to be developed in ch11). Israel has no excuse for not hearing: Moses himself predicted the Gentile inclusion as Israel\'s provocation to jealousy.</p>',
    "20": '<p><strong>εὑρέθην τοῖς ἐμὲ μὴ ζητοῦσιν, ἐμφανὴς ἐγενόμην τοῖς ἐμὲ μὴ ἐπερωτῶσιν</strong> — "I was found by those who were not seeking me; I revealed myself to those who were not asking for me" — citing Isa 65:1. Isaiah spoke of God\'s willingness to be found even by the indifferent; Paul applies this to the Gentile inclusion. The parallel with 9:30 (Gentiles not pursuing righteousness who received it) reinforces: the Gentile reception was an act of divine initiative, not Gentile spiritual superiority.</p>',
    "21": '<p><strong>ὅλην τὴν ἡμέραν ἐξεπέτασα τὰς χεῖράς μου πρὸς λαὸν ἀπειθοῦντα καὶ ἀντιλέγοντα</strong> — "all day long I have stretched out my hands to a disobedient and contrary people" — citing Isa 65:2. The posture of the outstretched hands is the posture of welcome and pleading simultaneously; God\'s offer to Israel is continuous ("all day long"), earnest (stretched-out hands), and met with persistent refusal (<em>apeitheo</em> = disobey, disbelieve; <em>antilegō</em> = speak against, contradict). The chapter closes with divine longsuffering, not divine rejection — setting up ch11\'s argument that God has not abandoned Israel.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'romans')
    merge_comm(existing, ROMANS)
    save_comm('mkt-original', 'romans', existing)
    print('Romans 8–10 mkt-original written.')

if __name__ == '__main__':
    main()
